func ZEND_GENERATOR_CREATE_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var return_value *Zval = EX(return_value)
	if return_value != nil {
		var opline *ZendOp = EX(opline)
		var generator *ZendGenerator
		var gen_execute_data *ZendExecuteData
		var num_args uint32
		var used_stack uint32
		var call_info uint32
		ObjectInitEx(return_value, ZendCeGenerator)

		/*
		 * Normally the executeData is allocated on the VM stack (because it does
		 * not actually do any allocation and thus is faster). For generators
		 * though this behavior would be suboptimal, because the (rather large)
		 * structure would have to be copied back and forth every time execution is
		 * suspended or resumed. That's why for generators the execution context
		 * is allocated on heap.
		 */

		num_args = EX_NUM_ARGS()
		if num_args <= EX(func_).op_array.num_args {
			used_stack = (ZEND_CALL_FRAME_SLOT + EX(func_).op_array.last_var + EX(func_).op_array.T) * b.SizeOf("zval")
			gen_execute_data = (*ZendExecuteData)(Emalloc(used_stack))
			used_stack = (ZEND_CALL_FRAME_SLOT + EX(func_).op_array.last_var) * b.SizeOf("zval")
		} else {
			used_stack = (ZEND_CALL_FRAME_SLOT + num_args + EX(func_).op_array.last_var + EX(func_).op_array.T - EX(func_).op_array.num_args) * b.SizeOf("zval")
			gen_execute_data = (*ZendExecuteData)(Emalloc(used_stack))
		}
		memcpy(gen_execute_data, executeData, used_stack)

		/* Save execution context in generator object. */

		generator = (*ZendGenerator)(EX(return_value).GetObj())
		generator.SetExecuteData(gen_execute_data)
		generator.SetFrozenCallStack(nil)
		generator.GetExecuteFake().SetOpline(nil)
		generator.GetExecuteFake().SetFunc(nil)
		generator.GetExecuteFake().SetPrevExecuteData(nil)
		generator.GetExecuteFake().GetThis().SetObject((*ZendObject)(generator))
		gen_execute_data.SetOpline(opline + 1)

		/* EX(return_value) keeps pointer to zend_object (not a real zval) */

		gen_execute_data.SetReturnValue((*Zval)(generator))
		call_info = EX(This).GetTypeInfo()
		if (call_info&Z_TYPE_MASK) == IS_OBJECT && ((call_info&(ZEND_CALL_CLOSURE|ZEND_CALL_RELEASE_THIS)) == 0 || ZendExecuteEx != ExecuteEx) {
			ZEND_ADD_CALL_FLAG_EX(call_info, ZEND_CALL_RELEASE_THIS)
			gen_execute_data.GetThis().AddRefcount()
		}
		ZEND_ADD_CALL_FLAG_EX(call_info, ZEND_CALL_TOP_FUNCTION|ZEND_CALL_ALLOCATED|ZEND_CALL_GENERATOR)
		gen_execute_data.GetThis().GetTypeInfo() = call_info
		gen_execute_data.SetPrevExecuteData(nil)
		call_info = EX_CALL_INFO()
		EG__().SetCurrentExecuteData(EX(prev_execute_data))
		if (call_info & (ZEND_CALL_TOP | ZEND_CALL_ALLOCATED)) == 0 {
			EG__().SetVmStackTop((*Zval)(executeData))
			executeData = EX(prev_execute_data)
			LOAD_NEXT_OPLINE()
			return 2
		} else if (call_info & ZEND_CALL_TOP) == 0 {
			var old_execute_data *ZendExecuteData = executeData
			executeData = EX(prev_execute_data)
			ZendVmStackFreeCallFrameEx(call_info, old_execute_data)
			LOAD_NEXT_OPLINE()
			return 2
		} else {
			return -1
		}
	} else {
		return zend_leave_helper_SPEC(executeData)
	}
}
func zend_cannot_pass_by_ref_helper_SPEC(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var arg *Zval
	var arg_num uint32 = opline.GetOp2().GetNum()
	ZendThrowError(nil, "Cannot pass parameter %d by reference", arg_num)
	FREE_UNFETCHED_OP(opline.GetOp1Type(), opline.GetOp1().GetVar())
	arg = ZEND_CALL_VAR(EX(call), opline.GetResult().GetVar())
	arg.SetUndef()
	HANDLE_EXCEPTION()
}
func ZEND_SEND_UNPACK_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var args *Zval
	var arg_num int
	args = GetZvalPtrUndef(opline.GetOp1Type(), opline.GetOp1(), &free_op1, BP_VAR_R)
	arg_num = ZEND_CALL_NUM_ARGS(EX(call)) + 1
send_again:
	if args.IsArray() {
		var ht *HashTable = args.GetArr()
		var arg *Zval
		var top *Zval
		var name *ZendString
		ZendVmStackExtendCallFrame(&(EX(call)), arg_num-1, ht.GetNNumOfElements())
		if (opline.GetOp1Type()&(IS_VAR|IS_CV)) != 0 && args.GetRefcount() > 1 {
			var i uint32
			var separate int = 0

			/* check if any of arguments are going to be passed by reference */

			for i = 0; i < ht.GetNNumOfElements(); i++ {
				if ARG_SHOULD_BE_SENT_BY_REF(EX(call).func_, arg_num+i) != 0 {
					separate = 1
					break
				}
			}
			if separate != 0 {
				SEPARATE_ARRAY(args)
				ht = args.GetArr()
			}
		}
		var __ht *HashTable = ht
		for _, _p := range __ht.foreachData() {
			var _z *Zval = _p.GetVal()

			name = _p.GetKey()
			arg = _z
			if name != nil {
				ZendThrowError(nil, "Cannot unpack array with string keys")
				FREE_OP(free_op1)
				HANDLE_EXCEPTION()
			}
			top = EX(call).Arg(arg_num)
			if ARG_SHOULD_BE_SENT_BY_REF(EX(call).func_, arg_num) != 0 {
				if arg.IsReference() {
					arg.AddRefcount()
					top.SetReference(arg.GetRef())
				} else if (opline.GetOp1Type() & (IS_VAR | IS_CV)) != 0 {

					/* array is already separated above */

					ZVAL_MAKE_REF_EX(arg, 2)
					top.SetReference(arg.GetRef())
				} else {
					arg.TryAddRefcount()
					top.SetNewRef(arg)
				}
			} else {
				ZVAL_COPY_DEREF(top, arg)
			}
			ZEND_CALL_NUM_ARGS(EX(call))++
			arg_num++
		}
	} else if args.IsObject() {
		var ce *ZendClassEntry = Z_OBJCE_P(args)
		var iter *ZendObjectIterator
		if ce == nil || ce.GetGetIterator() == nil {
			ZendError(E_WARNING, "Only arrays and Traversables can be unpacked")
		} else {
			iter = ce.GetGetIterator()(ce, args, 0)
			if iter == nil {
				FREE_OP(free_op1)
				if EG__().GetException() == nil {
					ZendThrowExceptionEx(nil, 0, "Object of type %s did not create an Iterator", ce.GetName().GetVal())
				}
				HANDLE_EXCEPTION()
			}
			if iter.GetFuncs().GetRewind() != nil {
				iter.GetFuncs().GetRewind()(iter)
			}
			for ; iter.GetFuncs().GetValid()(iter) == SUCCESS; arg_num++ {
				var arg *Zval
				var top *Zval
				if EG__().GetException() != nil {
					break
				}
				arg = iter.GetFuncs().GetGetCurrentData()(iter)
				if EG__().GetException() != nil {
					break
				}
				if iter.GetFuncs().GetGetCurrentKey() != nil {
					var key Zval
					iter.GetFuncs().GetGetCurrentKey()(iter, &key)
					if EG__().GetException() != nil {
						break
					}
					if key.GetType() != IS_LONG {
						ZendThrowError(nil, b.Cond(key.IsString(), "Cannot unpack Traversable with string keys", "Cannot unpack Traversable with non-integer keys"))
						ZvalPtrDtor(&key)
						break
					}
				}
				if ARG_MUST_BE_SENT_BY_REF(EX(call).func_, arg_num) != 0 {
					ZendError(E_WARNING, "Cannot pass by-reference argument %d of %s%s%s()"+" by unpacking a Traversable, passing by-value instead", arg_num, b.CondF1(EX(call).func_.common.scope, func() []byte { return EX(call).func_.common.scope.name.GetVal() }, ""), b.Cond(EX(call).func_.common.scope, "::", ""), EX(call).func_.common.function_name.GetVal())
				}
				arg = ZVAL_DEREF(arg)
				arg.TryAddRefcount()
				ZendVmStackExtendCallFrame(&(EX(call)), arg_num-1, 1)
				top = EX(call).Arg(arg_num)
				ZVAL_COPY_VALUE(top, arg)
				ZEND_CALL_NUM_ARGS(EX(call))++
				iter.GetFuncs().GetMoveForward()(iter)
			}
			ZendIteratorDtor(iter)
		}
	} else if args.IsReference() {
		args = Z_REFVAL_P(args)
		goto send_again
	} else {
		if opline.GetOp1Type() == IS_CV && args.IsUndef() {
			ZVAL_UNDEFINED_OP1()
		}
		ZendError(E_WARNING, "Only arrays and Traversables can be unpacked")
	}
	FREE_OP(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_SEND_ARRAY_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var args *Zval
	args = GetZvalPtr(opline.GetOp1Type(), opline.GetOp1(), &free_op1, BP_VAR_R)
	if args.GetType() != IS_ARRAY {
		if (opline.GetOp1Type()&(IS_VAR|IS_CV)) != 0 && args.IsReference() {
			args = Z_REFVAL_P(args)
			if args.IsArray() {
				goto send_array
			}
		}
		ZendInternalTypeError(executeData.IsCallUseStrictTypes(), "call_user_func_array() expects parameter 2 to be array, %s given", ZendGetTypeByConst(args.GetType()))
		if (ZEND_CALL_INFO(EX(call)) & ZEND_CALL_CLOSURE) != 0 {
			OBJ_RELEASE(ZEND_CLOSURE_OBJECT(EX(call).func_))
		} else if (ZEND_CALL_INFO(EX(call)) & ZEND_CALL_RELEASE_THIS) != 0 {
			OBJ_RELEASE(EX(call).This.GetObj())
		}
		EX(call).func_ = (*ZendFunction)(&ZendPassFunction)
		EX(call).This.GetObj() = nil
		ZEND_CALL_INFO(EX(call)) &= ^(ZEND_CALL_RELEASE_THIS | ZEND_CALL_HAS_THIS)
		FREE_UNFETCHED_OP(opline.GetOp2Type(), opline.GetOp2().GetVar())
	} else {
		var arg_num uint32
		var ht *HashTable
		var arg *Zval
		var param *Zval
	send_array:
		ht = args.GetArr()
		if opline.GetOp2Type() != IS_UNUSED {
			var free_op2 ZendFreeOp
			var op2 *Zval = GetZvalPtr(opline.GetOp2Type(), opline.GetOp2(), &free_op2, BP_VAR_R)
			var skip uint32 = opline.GetExtendedValue()
			var count uint32 = ht.GetNNumOfElements()
			var len_ ZendLong = ZvalGetLong(op2)
			if len_ < 0 {
				len_ += zend_long(count - skip)
			}
			if skip < count && len_ > 0 {
				if len_ > zend_long(count-skip) {
					len_ = zend_long(count - skip)
				}
				ZendVmStackExtendCallFrame(&(EX(call)), 0, len_)
				arg_num = 1
				param = EX(call).Arg(1)
				var __ht *HashTable = ht
				for _, _p := range __ht.foreachData() {
					var _z *Zval = _p.GetVal()

					arg = _z
					var must_wrap ZendBool = 0
					if skip > 0 {
						skip--
						continue
					} else if zend_long(arg_num-1) >= len_ {
						break
					} else if ARG_SHOULD_BE_SENT_BY_REF(EX(call).func_, arg_num) != 0 {
						if !(arg.IsReference()) {
							if ARG_MAY_BE_SENT_BY_REF(EX(call).func_, arg_num) == 0 {

								/* By-value send is not allowed -- emit a warning,
								 * but still perform the call. */

								ZendParamMustBeRef(EX(call).func_, arg_num)
								must_wrap = 1
							}
						}
					} else {
						if arg.IsReference() && (EX(call).func_.common.fn_flags&ZEND_ACC_CALL_VIA_TRAMPOLINE) == 0 {

							/* don't separate references for __call */

							arg = Z_REFVAL_P(arg)

							/* don't separate references for __call */

						}
					}
					if must_wrap == 0 {
						ZVAL_COPY(param, arg)
					} else {
						arg.TryAddRefcount()
						param.SetNewRef(arg)
					}
					ZEND_CALL_NUM_ARGS(EX(call))++
					arg_num++
					param++
				}
			}
			FREE_OP(free_op2)
		} else {
			ZendVmStackExtendCallFrame(&(EX(call)), 0, ht.GetNNumOfElements())
			arg_num = 1
			param = EX(call).Arg(1)
			var __ht *HashTable = ht
			for _, _p := range __ht.foreachData() {
				var _z *Zval = _p.GetVal()

				arg = _z
				var must_wrap ZendBool = 0
				if ARG_SHOULD_BE_SENT_BY_REF(EX(call).func_, arg_num) != 0 {
					if !(arg.IsReference()) {
						if ARG_MAY_BE_SENT_BY_REF(EX(call).func_, arg_num) == 0 {

							/* By-value send is not allowed -- emit a warning,
							 * but still perform the call. */

							ZendParamMustBeRef(EX(call).func_, arg_num)
							must_wrap = 1
						}
					}
				} else {
					if arg.IsReference() && (EX(call).func_.common.fn_flags&ZEND_ACC_CALL_VIA_TRAMPOLINE) == 0 {

						/* don't separate references for __call */

						arg = Z_REFVAL_P(arg)

						/* don't separate references for __call */

					}
				}
				if must_wrap == 0 {
					ZVAL_COPY(param, arg)
				} else {
					arg.TryAddRefcount()
					param.SetNewRef(arg)
				}
				ZEND_CALL_NUM_ARGS(EX(call))++
				arg_num++
				param++
			}
		}
	}
	FREE_OP(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func zend_case_helper_SPEC(op_1 *Zval, op_2 *Zval, executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if op_1.GetTypeInfo() == IS_UNDEF {
		op_1 = ZVAL_UNDEFINED_OP1()
	}
	if op_2.GetTypeInfo() == IS_UNDEF {
		op_2 = ZVAL_UNDEFINED_OP2()
	}
	CompareFunction(EX_VAR(opline.GetResult().GetVar()), op_1, op_2)
	if (opline.GetOp2Type() & (IS_TMP_VAR | IS_VAR)) != 0 {
		ZvalPtrDtorNogc(op_2)
	}
	if EG__().GetException() != nil {
		HANDLE_EXCEPTION()
	}
	if EX_VAR(opline.GetResult().GetVar()).GetLval() == 0 {
		ZEND_VM_SMART_BRANCH_TRUE()
		EX_VAR(opline.GetResult().GetVar()).SetTrue()
		ZEND_VM_NEXT_OPCODE()
	} else {
		ZEND_VM_SMART_BRANCH_FALSE()
		EX_VAR(opline.GetResult().GetVar()).SetFalse()
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_ADD_ARRAY_UNPACK_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var op1 *Zval
	op1 = GetZvalPtr(opline.GetOp1Type(), opline.GetOp1(), &free_op1, BP_VAR_R)
add_unpack_again:
	if op1.IsArray() {
		var ht *HashTable = op1.GetArr()
		var val *Zval
		var key *ZendString
		var __ht *HashTable = ht
		for _, _p := range __ht.foreachData() {
			var _z *Zval = _p.GetVal()

			key = _p.GetKey()
			val = _z
			if key != nil {
				ZendThrowError(nil, "Cannot unpack array with string keys")
				FREE_OP(free_op1)
				HANDLE_EXCEPTION()
			} else {
				if val.IsReference() && val.GetRefcount() == 1 {
					val = Z_REFVAL_P(val)
				}
				val.TryAddRefcount()
				if EX_VAR(opline.GetResult().GetVar()).GetArr().NextIndexInsert(val) == nil {
					ZendCannotAddElement()
					ZvalPtrDtorNogc(val)
					break
				}
			}
		}
	} else if op1.IsObject() {
		var ce *ZendClassEntry = Z_OBJCE_P(op1)
		var iter *ZendObjectIterator
		if ce == nil || ce.GetGetIterator() == nil {
			ZendThrowError(nil, "Only arrays and Traversables can be unpacked")
		} else {
			iter = ce.GetGetIterator()(ce, op1, 0)
			if iter == nil {
				FREE_OP(free_op1)
				if EG__().GetException() == nil {
					ZendThrowExceptionEx(nil, 0, "Object of type %s did not create an Iterator", ce.GetName().GetVal())
				}
				HANDLE_EXCEPTION()
			}
			if iter.GetFuncs().GetRewind() != nil {
				iter.GetFuncs().GetRewind()(iter)
			}
			for iter.GetFuncs().GetValid()(iter) == SUCCESS {
				var val *Zval
				if EG__().GetException() != nil {
					break
				}
				val = iter.GetFuncs().GetGetCurrentData()(iter)
				if EG__().GetException() != nil {
					break
				}
				if iter.GetFuncs().GetGetCurrentKey() != nil {
					var key Zval
					iter.GetFuncs().GetGetCurrentKey()(iter, &key)
					if EG__().GetException() != nil {
						break
					}
					if key.GetType() != IS_LONG {
						ZendThrowError(nil, b.Cond(key.IsString(), "Cannot unpack Traversable with string keys", "Cannot unpack Traversable with non-integer keys"))
						ZvalPtrDtor(&key)
						break
					}
				}
				val = ZVAL_DEREF(val)
				val.TryAddRefcount()
				if EX_VAR(opline.GetResult().GetVar()).GetArr().NextIndexInsert(val) == nil {
					ZendCannotAddElement()
					ZvalPtrDtorNogc(val)
				}
				iter.GetFuncs().GetMoveForward()(iter)
			}
			ZendIteratorDtor(iter)
		}
	} else if op1.IsReference() {
		op1 = Z_REFVAL_P(op1)
		goto add_unpack_again
	} else {
		ZendThrowError(nil, "Only arrays and Traversables can be unpacked")
	}
	FREE_OP(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_UNSET_STATIC_PROP_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var varname *Zval
	var name *ZendString
	var tmp_name *ZendString = nil
	var ce *ZendClassEntry
	var free_op1 ZendFreeOp
	if opline.GetOp2Type() == IS_CONST {
		ce = CACHED_PTR(opline.GetExtendedValue())
		if ce == nil {
			ce = ZendFetchClassByName(RT_CONSTANT(opline, opline.GetOp2()).GetStr(), (RT_CONSTANT(opline, opline.GetOp2()) + 1).GetStr(), ZEND_FETCH_CLASS_DEFAULT|ZEND_FETCH_CLASS_EXCEPTION)
			if ce == nil {
				ZEND_ASSERT(EG__().GetException() != nil)
				FREE_UNFETCHED_OP(opline.GetOp1Type(), opline.GetOp1().GetVar())
				HANDLE_EXCEPTION()
			}
		}
	} else if opline.GetOp2Type() == IS_UNUSED {
		ce = ZendFetchClass(nil, opline.GetOp2().GetNum())
		if ce == nil {
			ZEND_ASSERT(EG__().GetException() != nil)
			FREE_UNFETCHED_OP(opline.GetOp1Type(), opline.GetOp1().GetVar())
			HANDLE_EXCEPTION()
		}
	} else {
		ce = EX_VAR(opline.GetOp2().GetVar()).GetCe()
	}
	varname = GetZvalPtrUndef(opline.GetOp1Type(), opline.GetOp1(), &free_op1, BP_VAR_R)
	if opline.GetOp1Type() == IS_CONST {
		name = varname.GetStr()
	} else if varname.IsString() {
		name = varname.GetStr()
	} else {
		if opline.GetOp1Type() == IS_CV && varname.IsUndef() {
			varname = ZVAL_UNDEFINED_OP1()
		}
		name = ZvalGetTmpString(varname, &tmp_name)
	}
	ZendStdUnsetStaticProperty(ce, name)
	ZendTmpStringRelease(tmp_name)
	FREE_OP(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_ISSET_ISEMPTY_STATIC_PROP_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result int
	result = ZendFetchStaticPropertyAddress(&value, nil, opline.GetExtendedValue() & ^ZEND_ISEMPTY, BP_VAR_IS, 0, opline, executeData)
	if (opline.GetExtendedValue() & ZEND_ISEMPTY) == 0 {
		result = result == SUCCESS && value.GetType() > IS_NULL && (!(value.IsReference()) || Z_REFVAL_P(value).GetType() != IS_NULL)
	} else {
		result = result != SUCCESS || IZendIsTrue(value) == 0
	}
	ZEND_VM_SMART_BRANCH(result, 1)
	ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result != 0)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_EXIT_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if opline.GetOp1Type() != IS_UNUSED {
		var free_op1 ZendFreeOp
		var ptr *Zval = GetZvalPtr(opline.GetOp1Type(), opline.GetOp1(), &free_op1, BP_VAR_R)
		for {
			if ptr.IsLong() {
				EG__().SetExitStatus(ptr.GetLval())
			} else {
				if (opline.GetOp1Type()&(IS_VAR|IS_CV)) != 0 && ptr.IsReference() {
					ptr = Z_REFVAL_P(ptr)
					if ptr.IsLong() {
						EG__().SetExitStatus(ptr.GetLval())
						break
					}
				}
				ZendPrintZval(ptr, 0)
			}
			break
		}
		FREE_OP(free_op1)
	}
	ZendBailout()
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_BEGIN_SILENCE_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	EX_VAR(opline.GetResult().GetVar()).SetLong(EG__().GetErrorReporting())
	if EG__().GetErrorReporting() != 0 {
		for {
			EG__().SetErrorReporting(0)
			if EG__().GetErrorReportingIniEntry() == nil {
				var zv *Zval = EG__().GetIniDirectives().KeyFind(ZSTR_KNOWN(ZEND_STR_ERROR_REPORTING).GetStr())
				if zv != nil {
					EG__().SetErrorReportingIniEntry((*ZendIniEntry)(zv.GetPtr()))
				} else {
					break
				}
			}
			if EG__().GetErrorReportingIniEntry().GetModified() == 0 {
				if EG__().GetModifiedIniDirectives() == nil {
					ALLOC_HASHTABLE(EG__().GetModifiedIniDirectives())
					ZendHashInit(EG__().GetModifiedIniDirectives(), 8, nil, nil, 0)
				}
				if ZendHashAddPtr(EG__().GetModifiedIniDirectives(), ZSTR_KNOWN(ZEND_STR_ERROR_REPORTING), EG__().GetErrorReportingIniEntry()) != nil {
					EG__().GetErrorReportingIniEntry().SetOrigValue(EG__().GetErrorReportingIniEntry().GetValue())
					EG__().GetErrorReportingIniEntry().SetOrigModifiable(EG__().GetErrorReportingIniEntry().GetModifiable())
					EG__().GetErrorReportingIniEntry().SetModified(1)
				}
			}
			break
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
