func ZEND_DECLARE_ANON_CLASS_SPEC_HANDLER(executeData *ZendExecuteData) int {
	var zv *Zval
	var ce *ZendClassEntry
	var opline *ZendOp = EX(opline)
	ce = CACHED_PTR(opline.GetExtendedValue())
	if ce == nil {
		var rtd_key *ZendString = RT_CONSTANT(opline, opline.GetOp1()).GetStr()
		zv = EG__().GetClassTable().KeyFind(rtd_key.GetStr())
		if zv == nil {
			for {
				ZEND_ASSERT((EX(func_).op_array.fn_flags & ZEND_ACC_PRELOADED) != 0)
				if ZendPreloadAutoload != nil && ZendPreloadAutoload(EX(func_).op_array.filename) == SUCCESS {
					zv = EG__().GetClassTable().KeyFind(rtd_key.GetStr())
					if zv != nil {
						break
					}
				}
				ZendErrorNoreturn(E_ERROR, "Anonymous class wasn't preloaded")
				break
			}
		}
		ZEND_ASSERT(zv != nil)
		ce = zv.GetCe()
		if !ce.IsLinked() {
			if ZendDoLinkClass(ce, b.CondF1(opline.GetOp2Type() == IS_CONST, func() *ZendString { return RT_CONSTANT(opline, opline.GetOp2()).GetStr() }, nil)) == FAILURE {
				HANDLE_EXCEPTION()
			}
		}
		CACHE_PTR(opline.GetExtendedValue(), ce)
	}
	EX_VAR(opline.GetResult().GetVar()).SetCe(ce)
	ZEND_VM_NEXT_OPCODE()
}
