	if uint32(b.PreInc(&(EG__().GetTicksCount())) >= opline.GetExtendedValue()) != 0 {
		EG__().SetTicksCount(0)
		if ZendTicksFunction != nil {
			ZendTicksFunction(opline.GetExtendedValue())
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
	}
	ZEND_VM_NEXT_OPCODE()
