func ZEND_FUNC_GET_ARGS_SPEC_CONST_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var ht *ZendArray
	var arg_count uint32
	var result_size uint32
	var skip uint32
	arg_count = EX_NUM_ARGS()
	if IS_CONST == IS_CONST {
		skip = RT_CONSTANT(opline, opline.GetOp1()).GetLval()
		if arg_count < skip {
			result_size = 0
		} else {
			result_size = arg_count - skip
		}
	} else {
		skip = 0
		result_size = arg_count
	}
	if result_size != 0 {
		var first_extra_arg uint32 = EX(func_).op_array.num_args
		ht = ZendNewArray(result_size)
		EX_VAR(opline.GetResult().GetVar()).SetArray(ht)
		ZendHashRealInitPacked(ht)
		var __fill_ht *HashTable = ht
		var __fill_bkt *Bucket = __fill_ht.GetArData() + __fill_ht.GetNNumUsed()
		var __fill_idx uint32 = __fill_ht.GetNNumUsed()
		ZEND_ASSERT(__fill_ht.HasUFlags(HASH_FLAG_PACKED))
		var p *Zval
		var q *Zval
		var i uint32 = skip
		p = EX_VAR_NUM(i)
		if arg_count > first_extra_arg {
			for i < first_extra_arg {
				q = p
				if q.GetTypeInfo() != IS_UNDEF {
					q = ZVAL_DEREF(q)
					if q.IsRefcounted() {
						q.AddRefcount()
					}
					ZVAL_COPY_VALUE(__fill_bkt.GetVal(), q)
				} else {
					__fill_bkt.GetVal().SetNull()
				}
				__fill_bkt.SetH(__fill_idx)
				__fill_bkt.SetKey(nil)
				__fill_bkt++
				__fill_idx++
				p++
				i++
			}
			if skip < first_extra_arg {
				skip = 0
			} else {
				skip -= first_extra_arg
			}
			p = EX_VAR_NUM(EX(func_).op_array.last_var + EX(func_).op_array.T + skip)
		}
		for i < arg_count {
			q = p
			if q.GetTypeInfo() != IS_UNDEF {
				q = ZVAL_DEREF(q)
				if q.IsRefcounted() {
					q.AddRefcount()
				}
				ZVAL_COPY_VALUE(__fill_bkt.GetVal(), q)
			} else {
				__fill_bkt.GetVal().SetNull()
			}
			__fill_bkt.SetH(__fill_idx)
			__fill_bkt.SetKey(nil)
			__fill_bkt++
			__fill_idx++
			p++
			i++
		}
		__fill_ht.SetNNumUsed(__fill_idx)
		__fill_ht.SetNNumOfElements(__fill_idx)
		__fill_ht.SetNNextFreeElement(__fill_idx)
		__fill_ht.SetNInternalPointer(0)
		ht.SetNNumOfElements(result_size)
	} else {
		ZVAL_EMPTY_ARRAY(EX_VAR(opline.GetResult().GetVar()))
	}
	ZEND_VM_NEXT_OPCODE()
}
