func ZEND_CLONE_SPEC_TMPVAR_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var obj *Zval
	var ce *ZendClassEntry
	var scope *ZendClassEntry
	var clone *ZendFunction
	var clone_call ZendObjectCloneObjT
	obj = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
	if (IS_TMP_VAR|IS_VAR) == IS_UNUSED && obj.IsUndef() {
		return zend_this_not_in_object_context_helper_SPEC(executeData)
	}
	for {
		if (IS_TMP_VAR|IS_VAR) == IS_CONST || (IS_TMP_VAR|IS_VAR) != IS_UNUSED && obj.GetType() != IS_OBJECT {
			if ((IS_TMP_VAR|IS_VAR)&(IS_VAR|IS_CV)) != 0 && obj.IsReference() {
				obj = Z_REFVAL_P(obj)
				if obj.IsObject() {
					break
				}
			}
			EX_VAR(opline.GetResult().GetVar()).SetUndef()
			if (IS_TMP_VAR|IS_VAR) == IS_CV && obj.IsUndef() {
				ZVAL_UNDEFINED_OP1()
				if EG__().GetException() != nil {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "__clone method called on non-object")
			ZvalPtrDtorNogc(free_op1)
			HANDLE_EXCEPTION()
		}
		break
	}
	ce = Z_OBJCE_P(obj)
	clone = ce.GetClone()
	clone_call = Z_OBJ_HT_P(obj).GetCloneObj()
	if clone_call == nil {
		ZendThrowError(nil, "Trying to clone an uncloneable object of class %s", ce.GetName().GetVal())
		ZvalPtrDtorNogc(free_op1)
		EX_VAR(opline.GetResult().GetVar()).SetUndef()
		HANDLE_EXCEPTION()
	}
	if clone != nil && !clone.IsPublic() {
		scope = EX(func_).op_array.scope
		if clone.GetScope() != scope {
			if clone.IsPrivate() || ZendCheckProtected(ZendGetFunctionRootClass(clone), scope) == 0 {
				ZendWrongCloneCall(clone, scope)
				ZvalPtrDtorNogc(free_op1)
				EX_VAR(opline.GetResult().GetVar()).SetUndef()
				HANDLE_EXCEPTION()
			}
		}
	}
	EX_VAR(opline.GetResult().GetVar()).SetObject(clone_call(obj))
	ZvalPtrDtorNogc(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INCLUDE_OR_EVAL_SPEC_TMPVAR_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var new_op_array *ZendOpArray
	var free_op1 ZendFreeOp
	var inc_filename *Zval
	inc_filename = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
	new_op_array = ZendIncludeOrEval(inc_filename, opline.GetExtendedValue())
	ZvalPtrDtorNogc(free_op1)
	if EG__().GetException() != nil {
		if new_op_array != ZEND_FAKE_OP_ARRAY && new_op_array != nil {
			DestroyOpArray(new_op_array)
			EfreeSize(new_op_array, b.SizeOf("zend_op_array"))
		}
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	} else if new_op_array == ZEND_FAKE_OP_ARRAY {
		if RETURN_VALUE_USED(opline) {
			EX_VAR(opline.GetResult().GetVar()).SetTrue()
		}
	} else if new_op_array != nil {
		var return_value *Zval = nil
		var call *ZendExecuteData
		if RETURN_VALUE_USED(opline) {
			return_value = EX_VAR(opline.GetResult().GetVar())
		}
		new_op_array.SetScope(EX(func_).op_array.scope)
		call = ZendVmStackPushCallFrame(EX(This).GetTypeInfo()&ZEND_CALL_HAS_THIS|ZEND_CALL_NESTED_CODE|ZEND_CALL_HAS_SYMBOL_TABLE, (*ZendFunction)(new_op_array), 0, EX(This).GetPtr())
		if (EX_CALL_INFO() & ZEND_CALL_HAS_SYMBOL_TABLE) != 0 {
			call.SetSymbolTable(EX(symbol_table))
		} else {
			call.SetSymbolTable(ZendRebuildSymbolTable())
		}
		call.SetPrevExecuteData(executeData)
		IInitCodeExecuteData(call, new_op_array, return_value)
		if ZendExecuteEx == ExecuteEx {
			return 1
		} else {
			ZEND_ADD_CALL_FLAG(call, ZEND_CALL_TOP)
			ZendExecuteEx(call)
			ZendVmStackFreeCallFrame(call)
		}
		DestroyOpArray(new_op_array)
		EfreeSize(new_op_array, b.SizeOf("zend_op_array"))
		if EG__().GetException() != nil {
			ZendRethrowException(executeData)
			UNDEF_RESULT()
			HANDLE_EXCEPTION()
		}
	} else if RETURN_VALUE_USED(opline) {
		EX_VAR(opline.GetResult().GetVar()).SetFalse()
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_STRLEN_SPEC_TMPVAR_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var free_op1 ZendFreeOp
	value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
	if value.IsString() {
		EX_VAR(opline.GetResult().GetVar()).SetLong(Z_STRLEN_P(value))
		ZvalPtrDtorNogc(free_op1)
		ZEND_VM_NEXT_OPCODE()
	} else {
		var strict ZendBool
		if ((IS_TMP_VAR|IS_VAR)&(IS_VAR|IS_CV)) != 0 && value.IsReference() {
			value = Z_REFVAL_P(value)
			if value.IsString() {
				EX_VAR(opline.GetResult().GetVar()).SetLong(Z_STRLEN_P(value))
				ZvalPtrDtorNogc(free_op1)
				ZEND_VM_NEXT_OPCODE()
			}
		}
		if (IS_TMP_VAR|IS_VAR) == IS_CV && value.IsUndef() {
			value = ZVAL_UNDEFINED_OP1()
		}
		strict = executeData.IsCallUseStrictTypes()
		for {
			if strict == 0 {
				var str *ZendString
				var tmp Zval
				ZVAL_COPY(&tmp, value)
				if ZendParseArgStrWeak(&tmp, &str) != 0 {
					EX_VAR(opline.GetResult().GetVar()).SetLong(str.GetLen())
					ZvalPtrDtor(&tmp)
					break
				}
				ZvalPtrDtor(&tmp)
			}
			if EG__().GetException() == nil {
				ZendInternalTypeError(strict, "strlen() expects parameter 1 to be string, %s given", ZendGetTypeByConst(value.GetType()))
			}
			EX_VAR(opline.GetResult().GetVar()).SetNull()
			break
		}
	}
	ZvalPtrDtorNogc(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_TYPE_CHECK_SPEC_TMPVAR_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result int = 0
	var free_op1 ZendFreeOp
	value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
	if (opline.GetExtendedValue() >> uint32(value.GetType()) & 1) != 0 {
	type_check_resource:
		if value.GetType() != IS_RESOURCE || nil != ZendRsrcListGetRsrcType(value.GetRes()) {
			result = 1
		}
	} else if ((IS_TMP_VAR|IS_VAR)&(IS_CV|IS_VAR)) != 0 && value.IsReference() {
		value = Z_REFVAL_P(value)
		if (opline.GetExtendedValue() >> uint32(value.GetType()) & 1) != 0 {
			goto type_check_resource
		}
	} else if (IS_TMP_VAR|IS_VAR) == IS_CV && value.IsUndef() {
		result = (1 << IS_NULL & opline.GetExtendedValue()) != 0
		ZVAL_UNDEFINED_OP1()
		if EG__().GetException() != nil {
			EX_VAR(opline.GetResult().GetVar()).SetUndef()
			HANDLE_EXCEPTION()
		}
	}
	if ((IS_TMP_VAR | IS_VAR) & (IS_TMP_VAR | IS_VAR)) != 0 {
		ZvalPtrDtorNogc(free_op1)
		ZEND_VM_SMART_BRANCH(result, 1)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result != 0)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	} else {
		ZEND_VM_SMART_BRANCH(result, 0)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result != 0)
		ZEND_VM_NEXT_OPCODE()
	}
}
