func ZEND_CAST_SPEC_TMP_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var expr *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	var ht *HashTable
	expr = _getZvalPtrTmp(opline.GetOp1().GetVar(), &free_op1, executeData)
	switch opline.GetExtendedValue() {
	case IS_NULL:
		result.SetNull()
	case _IS_BOOL:
		ZVAL_BOOL(result, ZendIsTrue(expr) != 0)
	case IS_LONG:
		result.SetLong(ZvalGetLong(expr))
	case IS_DOUBLE:
		result.SetDouble(ZvalGetDouble(expr))
	case IS_STRING:
		result.SetString(ZvalGetString(expr))
	default:
		if (IS_TMP_VAR & (IS_VAR | IS_CV)) != 0 {
			expr = ZVAL_DEREF(expr)
		}

		/* If value is already of correct type, return it directly */

		if expr.IsType(opline.GetExtendedValue()) {
			ZVAL_COPY_VALUE(result, expr)
			if IS_TMP_VAR == IS_CONST {
				if result.IsRefcounted() {
					result.AddRefcount()
				}
			} else if IS_TMP_VAR != IS_TMP_VAR {
				if result.IsRefcounted() {
					result.AddRefcount()
				}
			}
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
		if opline.GetExtendedValue() == IS_ARRAY {
			if IS_TMP_VAR == IS_CONST || expr.GetType() != IS_OBJECT || Z_OBJCE_P(expr) == ZendCeClosure {
				if expr.GetType() != IS_NULL {
					result.SetArray(ZendNewArray(1))
					expr = result.GetArr().IndexAddNewH(0, expr)
					if IS_TMP_VAR == IS_CONST {
						if expr.IsRefcounted() {
							expr.AddRefcount()
						}
					} else {
						if expr.IsRefcounted() {
							expr.AddRefcount()
						}
					}
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			} else {
				var obj_ht *HashTable = ZendGetPropertiesFor(expr, ZEND_PROP_PURPOSE_ARRAY_CAST)
				if obj_ht != nil {

					/* fast copy */

					result.SetArray(ZendProptableToSymtable(obj_ht, Z_OBJCE_P(expr).GetDefaultPropertiesCount() != 0 || Z_OBJ_P(expr).GetHandlers() != &StdObjectHandlers || obj_ht.IsRecursive()))
					ZendReleaseProperties(obj_ht)
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			}
		} else {
			result.SetObject(ZendObjectsNew(ZendStandardClassDef))
			if expr.IsArray() {
				ht = ZendSymtableToProptable(expr.GetArr())
				if (ht.GetGcFlags() & IS_ARRAY_IMMUTABLE) != 0 {

					/* TODO: try not to duplicate immutable arrays as well ??? */

					ht = ZendArrayDup(ht)

					/* TODO: try not to duplicate immutable arrays as well ??? */

				}
				Z_OBJ_P(result).SetProperties(ht)
			} else if expr.GetType() != IS_NULL {
				ht = ZendNewArray(1)
				Z_OBJ_P(result).SetProperties(ht)
				expr = ht.KeyAddNew(ZSTR_KNOWN(ZEND_STR_SCALAR).GetStr(), expr)
				if IS_TMP_VAR == IS_CONST {
					if expr.IsRefcounted() {
						expr.AddRefcount()
					}
				} else {
					if expr.IsRefcounted() {
						expr.AddRefcount()
					}
				}
			}
		}
	}
	ZvalPtrDtorNogc(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_FE_RESET_R_SPEC_TMP_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var array_ptr *Zval
	var result *Zval
	array_ptr = _getZvalPtrTmp(opline.GetOp1().GetVar(), &free_op1, executeData)
	if array_ptr.IsArray() {
		result = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, array_ptr)
		if IS_TMP_VAR != IS_TMP_VAR && result.IsRefcounted() {
			array_ptr.AddRefcount()
		}
		result.SetFePos(0)
		ZEND_VM_NEXT_OPCODE()
	} else if IS_TMP_VAR != IS_CONST && array_ptr.IsObject() {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if Z_OBJ_P(array_ptr).GetProperties() != nil && Z_OBJ_P(array_ptr).GetProperties().GetRefcount() > 1 {
				if (Z_OBJ_P(array_ptr).GetProperties().GetGcFlags() & IS_ARRAY_IMMUTABLE) == 0 {
					Z_OBJ_P(array_ptr).GetProperties().DelRefcount()
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			result = EX_VAR(opline.GetResult().GetVar())
			ZVAL_COPY_VALUE(result, array_ptr)
			if IS_TMP_VAR != IS_TMP_VAR {
				array_ptr.AddRefcount()
			}
			if properties.GetNNumOfElements() == 0 {
				result.SetFeIterIdx(uint32 - 1)
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			result.SetFeIterIdx(ZendHashIteratorAdd(properties, 0))
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 0, opline, executeData)
			ZvalPtrDtorNogc(free_op1)
			if EG__().GetException() != nil {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		EX_VAR(opline.GetResult().GetVar()).SetUndef()
		EX_VAR(opline.GetResult().GetVar()).SetFeIterIdx(uint32 - 1)
		ZvalPtrDtorNogc(free_op1)
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
