func ZEND_INIT_STATIC_METHOD_CALL_SPEC_VAR_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var ce *ZendClassEntry
	var call_info uint32
	var fbc *ZendFunction
	var call *ZendExecuteData
	if IS_VAR == IS_CONST {

		/* no function found. try a static method in class */

		ce = CACHED_PTR(opline.GetResult().GetNum())
		if ce == nil {
			ce = ZendFetchClassByName(RT_CONSTANT(opline, opline.GetOp1()).GetStr(), (RT_CONSTANT(opline, opline.GetOp1()) + 1).GetStr(), ZEND_FETCH_CLASS_DEFAULT|ZEND_FETCH_CLASS_EXCEPTION)
			if ce == nil {
				ZEND_ASSERT(EG__().GetException() != nil)
				HANDLE_EXCEPTION()
			}
			if IS_CV != IS_CONST {
				CACHE_PTR(opline.GetResult().GetNum(), ce)
			}
		}
	} else if IS_VAR == IS_UNUSED {
		ce = ZendFetchClass(nil, opline.GetOp1().GetNum())
		if ce == nil {
			ZEND_ASSERT(EG__().GetException() != nil)
			HANDLE_EXCEPTION()
		}
	} else {
		ce = EX_VAR(opline.GetOp1().GetVar()).GetCe()
	}
	if IS_VAR == IS_CONST && IS_CV == IS_CONST && b.Assign(&fbc, CACHED_PTR(opline.GetResult().GetNum()+b.SizeOf("void *"))) != nil {

	} else if IS_VAR != IS_CONST && IS_CV == IS_CONST && CACHED_PTR(opline.GetResult().GetNum()) == ce {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else if IS_CV != IS_UNUSED {
		function_name = EX_VAR(opline.GetOp2().GetVar())
		if IS_CV != IS_CONST {
			if function_name.GetType() != IS_STRING {
				for {
					if (IS_CV&(IS_VAR|IS_CV)) != 0 && function_name.IsReference() {
						function_name = Z_REFVAL_P(function_name)
						if function_name.IsString() {
							break
						}
					} else if IS_CV == IS_CV && function_name.IsUndef() {
						ZVAL_UNDEFINED_OP2()
						if EG__().GetException() != nil {
							HANDLE_EXCEPTION()
						}
					}
					ZendThrowError(nil, "Function name must be a string")
					HANDLE_EXCEPTION()
					break
				}
			}
		}
		if ce.GetGetStaticMethod() != nil {
			fbc = ce.GetGetStaticMethod()(ce, function_name.GetStr())
		} else {
			fbc = ZendStdGetStaticMethod(ce, function_name.GetStr(), b.CondF1(IS_CV == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		}
		if fbc == nil {
			if EG__().GetException() == nil {
				ZendUndefinedMethod(ce, function_name.GetStr())
			}
			HANDLE_EXCEPTION()
		}
		if IS_CV == IS_CONST && fbc.GetType() <= ZEND_USER_FUNCTION && !fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), ce, fbc)
		}
		if fbc.GetType() == ZEND_USER_FUNCTION && !(RUN_TIME_CACHE(fbc.GetOpArray())) {
			InitFuncRunTimeCache(fbc.GetOpArray())
		}
		if IS_CV != IS_CONST {

		}
	} else {
		if ce.GetConstructor() == nil {
			ZendThrowError(nil, "Cannot call constructor")
			HANDLE_EXCEPTION()
		}
		if EX(This).u1.v.type_ == IS_OBJECT && Z_OBJ(EX(This)).GetCe() != ce.GetConstructor().GetScope() && ce.GetConstructor().IsPrivate() {
			ZendThrowError(nil, "Cannot call private %s::__construct()", ce.GetName().GetVal())
			HANDLE_EXCEPTION()
		}
		fbc = ce.GetConstructor()
		if fbc.GetType() == ZEND_USER_FUNCTION && !(RUN_TIME_CACHE(fbc.GetOpArray())) {
			InitFuncRunTimeCache(fbc.GetOpArray())
		}
	}
	if !fbc.IsStatic() {
		if EX(This).u1.v.type_ == IS_OBJECT && InstanceofFunction(Z_OBJCE(EX(This)), ce) != 0 {
			ce = (*ZendClassEntry)(EX(This).GetObj())
			call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
		} else {
			ZendNonStaticMethodCall(fbc)
			if EG__().GetException() != nil {
				HANDLE_EXCEPTION()
			}
			goto check_parent_and_self
		}
	} else {
	check_parent_and_self:

		/* previous opcode is ZEND_FETCH_CLASS */

		if IS_VAR == IS_UNUSED && ((opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_PARENT || (opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_SELF) {
			if EX(This).u1.v.type_ == IS_OBJECT {
				ce = Z_OBJCE(EX(This))
			} else {
				ce = EX(This).GetCe()
			}
		}
		call_info = ZEND_CALL_NESTED_FUNCTION
	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), ce)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ADD_ARRAY_ELEMENT_SPEC_VAR_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var expr_ptr *Zval
	var new_expr Zval
	if (IS_VAR == IS_VAR || IS_VAR == IS_CV) && (opline.GetExtendedValue()&ZEND_ARRAY_ELEMENT_REF) != 0 {
		expr_ptr = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
		if expr_ptr.IsReference() {
			expr_ptr.AddRefcount()
		} else {
			ZVAL_MAKE_REF_EX(expr_ptr, 2)
		}
		if free_op1 != nil {
			ZvalPtrDtorNogc(free_op1)
		}
	} else {
		expr_ptr = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
		if IS_VAR == IS_TMP_VAR {

		} else if IS_VAR == IS_CONST {
			expr_ptr.TryAddRefcount()
		} else if IS_VAR == IS_CV {
			expr_ptr = ZVAL_DEREF(expr_ptr)
			expr_ptr.TryAddRefcount()
		} else {
			if expr_ptr.IsReference() {
				var ref *ZendRefcounted = expr_ptr.GetCounted()
				expr_ptr = Z_REFVAL_P(expr_ptr)
				if ref.DelRefcount() == 0 {
					ZVAL_COPY_VALUE(&new_expr, expr_ptr)
					expr_ptr = &new_expr
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if expr_ptr.IsRefcounted() {
					expr_ptr.AddRefcount()
				}
			}
		}
	}
	if IS_CV != IS_UNUSED {
		var offset *Zval = EX_VAR(opline.GetOp2().GetVar())
		var str *ZendString
		var hval ZendUlong
	add_again:
		if offset.IsString() {
			str = offset.GetStr()
			if IS_CV != IS_CONST {
				if ZEND_HANDLE_NUMERIC(str, &hval) {
					goto num_index
				}
			}
		str_index:
			EX_VAR(opline.GetResult().GetVar()).GetArr().KeyUpdate(str.GetStr(), expr_ptr)
		} else if offset.IsLong() {
			hval = offset.GetLval()
		num_index:
			EX_VAR(opline.GetResult().GetVar()).GetArr().IndexUpdateH(hval, expr_ptr)
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && offset.IsReference() {
			offset = Z_REFVAL_P(offset)
			goto add_again
		} else if offset.IsNull() {
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else if offset.IsDouble() {
			hval = ZendDvalToLval(offset.GetDval())
			goto num_index
		} else if offset.IsFalse() {
			hval = 0
			goto num_index
		} else if offset.IsTrue() {
			hval = 1
			goto num_index
		} else if offset.IsResource() {
			ZendUseResourceAsOffset(offset)
			hval = Z_RES_HANDLE_P(offset)
			goto num_index
		} else if IS_CV == IS_CV && offset.IsUndef() {
			ZVAL_UNDEFINED_OP2()
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else {
			ZendIllegalOffset()
			ZvalPtrDtorNogc(expr_ptr)
		}
	} else {
		if EX_VAR(opline.GetResult().GetVar()).GetArr().NextIndexInsert(expr_ptr) == nil {
			ZendCannotAddElement()
			ZvalPtrDtorNogc(expr_ptr)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_ARRAY_SPEC_VAR_CV_HANDLER(executeData *ZendExecuteData) int {
	var array *Zval
	var size uint32
	var opline *ZendOp = EX(opline)
	array = EX_VAR(opline.GetResult().GetVar())
	if IS_VAR != IS_UNUSED {
		size = opline.GetExtendedValue() >> ZEND_ARRAY_SIZE_SHIFT
		array.SetArray(ZendNewArray(size))

		/* Explicitly initialize array as not-packed if flag is set */

		if (opline.GetExtendedValue() & ZEND_ARRAY_NOT_PACKED) != 0 {
			ZendHashRealInitMixed(array.GetArr())
		}
		return ZEND_ADD_ARRAY_ELEMENT_SPEC_VAR_CV_HANDLER(executeData)
	} else {
		array.SetArray(ZendNewArray(0))
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_UNSET_DIM_SPEC_VAR_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var container *Zval
	var offset *Zval
	var hval ZendUlong
	var key *ZendString
	container = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
	offset = EX_VAR(opline.GetOp2().GetVar())
	for {
		if container.IsArray() {
			var ht *HashTable
		unset_dim_array:
			SEPARATE_ARRAY(container)
			ht = container.GetArr()
		offset_again:
			if offset.IsString() {
				key = offset.GetStr()
				if IS_CV != IS_CONST {
					if ZEND_HANDLE_NUMERIC(key, &hval) {
						goto num_index_dim
					}
				}
			str_index_dim:
				if ht == EG__().GetSymbolTable() {
					ZendDeleteGlobalVariable(key)
				} else {
					ZendHashDel(ht, key)
				}
			} else if offset.IsLong() {
				hval = offset.GetLval()
			num_index_dim:
				ZendHashIndexDel(ht, hval)
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && offset.IsReference() {
				offset = Z_REFVAL_P(offset)
				goto offset_again
			} else if offset.IsDouble() {
				hval = ZendDvalToLval(offset.GetDval())
				goto num_index_dim
			} else if offset.IsNull() {
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else if offset.IsFalse() {
				hval = 0
				goto num_index_dim
			} else if offset.IsTrue() {
				hval = 1
				goto num_index_dim
			} else if offset.IsResource() {
				hval = Z_RES_HANDLE_P(offset)
				goto num_index_dim
			} else if IS_CV == IS_CV && offset.IsUndef() {
				ZVAL_UNDEFINED_OP2()
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else {
				ZendError(E_WARNING, "Illegal offset type in unset")
			}
			break
		} else if container.IsReference() {
			container = Z_REFVAL_P(container)
			if container.IsArray() {
				goto unset_dim_array
			}
		}
		if IS_VAR == IS_CV && container.IsUndef() {
			container = ZVAL_UNDEFINED_OP1()
		}
		if IS_CV == IS_CV && offset.IsUndef() {
			offset = ZVAL_UNDEFINED_OP2()
		}
		if container.IsObject() {
			if IS_CV == IS_CONST && offset.GetU2Extra() == ZEND_EXTRA_VALUE {
				offset++
			}
			Z_OBJ_HT_P(container).GetUnsetDimension()(container, offset)
		} else if IS_VAR != IS_UNUSED && container.IsString() {
			ZendThrowError(nil, "Cannot unset string offsets")
		}
		break
	}
	if free_op1 != nil {
		ZvalPtrDtorNogc(free_op1)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_UNSET_OBJ_SPEC_VAR_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var container *Zval
	var offset *Zval
	container = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
	if IS_VAR == IS_UNUSED && container.IsUndef() {
		return zend_this_not_in_object_context_helper_SPEC(executeData)
	}
	offset = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), executeData)
	for {
		if IS_VAR != IS_UNUSED && container.GetType() != IS_OBJECT {
			if container.IsReference() {
				container = Z_REFVAL_P(container)
				if container.GetType() != IS_OBJECT {
					if IS_VAR == IS_CV && container.IsUndef() {
						ZVAL_UNDEFINED_OP1()
					}
					break
				}
			} else {
				break
			}
		}
		Z_OBJ_HT_P(container).GetUnsetProperty()(container, offset, b.CondF1(IS_CV == IS_CONST, func() *any { return CACHE_ADDR(opline.GetExtendedValue()) }, nil))
		break
	}
	if free_op1 != nil {
		ZvalPtrDtorNogc(free_op1)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_YIELD_SPEC_VAR_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(executeData)
	if generator.IsForcedClose() {
		return zend_yield_in_closed_generator_helper_SPEC(executeData)
	}

	/* Destroy the previously yielded value */

	ZvalPtrDtor(generator.GetValue())

	/* Destroy the previously yielded key */

	ZvalPtrDtor(generator.GetKey())

	/* Set the new yielded value */

	if IS_VAR != IS_UNUSED {
		var free_op1 ZendFreeOp
		if (EX(func_).op_array.fn_flags & ZEND_ACC_RETURN_REFERENCE) != 0 {

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

			if (IS_VAR & (IS_CONST | IS_TMP_VAR)) != 0 {
				var value *Zval
				ZendError(E_NOTICE, "Only variable references should be yielded by reference")
				value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)
				ZVAL_COPY_VALUE(generator.GetValue(), value)
				if IS_VAR == IS_CONST {
					if generator.GetValue().IsRefcounted() {
						generator.GetValue().AddRefcount()
					}
				}
			} else {
				var value_ptr *Zval = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

				for {
					if IS_VAR == IS_VAR {
						ZEND_ASSERT(value_ptr != EG__().GetUninitializedZval())
						if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(value_ptr.IsReference()) {
							ZendError(E_NOTICE, "Only variable references should be yielded by reference")
							ZVAL_COPY(generator.GetValue(), value_ptr)
							break
						}
					}
					if value_ptr.IsReference() {
						value_ptr.AddRefcount()
					} else {
						ZVAL_MAKE_REF_EX(value_ptr, 2)
					}
					generator.GetValue().SetReference(value_ptr.GetRef())
					break
				}
				if free_op1 != nil {
					ZvalPtrDtorNogc(free_op1)
				}
			}

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

		} else {
			var value *Zval = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, executeData)

			/* Consts, temporary variables and references need copying */

			if IS_VAR == IS_CONST {
				ZVAL_COPY_VALUE(generator.GetValue(), value)
				if generator.GetValue().IsRefcounted() {
					generator.GetValue().AddRefcount()
				}
			} else if IS_VAR == IS_TMP_VAR {
				ZVAL_COPY_VALUE(generator.GetValue(), value)
			} else if (IS_VAR&(IS_VAR|IS_CV)) != 0 && value.IsReference() {
				ZVAL_COPY(generator.GetValue(), Z_REFVAL_P(value))
				ZvalPtrDtorNogc(free_op1)
			} else {
				ZVAL_COPY_VALUE(generator.GetValue(), value)
				if IS_VAR == IS_CV {
					if value.IsRefcounted() {
						value.AddRefcount()
					}
				}
			}

			/* Consts, temporary variables and references need copying */

		}
	} else {

		/* If no value was specified yield null */

		generator.GetValue().SetNull()

		/* If no value was specified yield null */

	}

	/* Set the new yielded key */

	if IS_CV != IS_UNUSED {
		var key *Zval = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), executeData)

		/* Consts, temporary variables and references need copying */

		if IS_CV == IS_CONST {
			ZVAL_COPY_VALUE(generator.GetKey(), key)
			if generator.GetKey().IsRefcounted() {
				generator.GetKey().AddRefcount()
			}
		} else if IS_CV == IS_TMP_VAR {
			ZVAL_COPY_VALUE(generator.GetKey(), key)
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && key.IsReference() {
			ZVAL_COPY(generator.GetKey(), Z_REFVAL_P(key))
		} else {
			ZVAL_COPY_VALUE(generator.GetKey(), key)
			if IS_CV == IS_CV {
				if key.IsRefcounted() {
					key.AddRefcount()
				}
			}
		}
		if generator.GetKey().IsLong() && generator.GetKey().GetLval() > generator.GetLargestUsedIntegerKey() {
			generator.SetLargestUsedIntegerKey(generator.GetKey().GetLval())
		}
	} else {

		/* If no key was specified we use auto-increment keys */

		generator.GetLargestUsedIntegerKey()++
		generator.GetKey().SetLong(generator.GetLargestUsedIntegerKey())
	}
	if RETURN_VALUE_USED(opline) {

		/* If the return value of yield is used set the send
		 * target and initialize it to NULL */

		generator.SetSendTarget(EX_VAR(opline.GetResult().GetVar()))
		generator.GetSendTarget().SetNull()
	} else {
		generator.SetSendTarget(nil)
	}

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in executeData so we don't resume at an old position. */

	return -1
}
func ZEND_FE_FETCH_R_SIMPLE_SPEC_VAR_CV_RETVAL_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array *Zval
	var value *Zval
	var variable_ptr *Zval
	var value_type uint32
	var fe_ht *HashTable
	var pos HashPosition
	var p *Bucket
	array = EX_VAR(opline.GetOp1().GetVar())
	fe_ht = array.GetArr()
	pos = array.GetFePos()
	p = fe_ht.GetArData() + pos
	for true {
		if pos >= fe_ht.GetNNumUsed() {

			/* reached end of iteration */

			ZEND_VM_SET_RELATIVE_OPCODE(opline, opline.GetExtendedValue())
			return 0
		}
		value = p.GetVal()
		value_type = value.GetTypeInfo()
		if value_type != IS_UNDEF {
			if value_type == IS_INDIRECT {
				value = value.GetZv()
				value_type = value.GetTypeInfo()
				if value_type != IS_UNDEF {
					break
				}
			} else {
				break
			}
		}
		pos++
		p++
	}
	array.SetFePos(pos + 1)

	variable_ptr = EX_VAR(opline.GetOp2().GetVar())
	ZendAssignToVariable(variable_ptr, value, IS_CV, executeData.IsCallUseStrictTypes())
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_FE_FETCH_R_SIMPLE_SPEC_VAR_CV_RETVAL_USED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array *Zval
	var value *Zval
	var variable_ptr *Zval
	var value_type uint32
	var fe_ht *HashTable
	var pos HashPosition
	var p *Bucket
	array = EX_VAR(opline.GetOp1().GetVar())
	fe_ht = array.GetArr()
	pos = array.GetFePos()
	p = fe_ht.GetArData() + pos
	for true {
		if pos >= fe_ht.GetNNumUsed() {

			/* reached end of iteration */

			ZEND_VM_SET_RELATIVE_OPCODE(opline, opline.GetExtendedValue())
			return 0
		}
		value = p.GetVal()
		value_type = value.GetTypeInfo()
		if value_type != IS_UNDEF {
			if value_type == IS_INDIRECT {
				value = value.GetZv()
				value_type = value.GetTypeInfo()
				if value_type != IS_UNDEF {
					break
				}
			} else {
				break
			}
		}
		pos++
		p++
	}
	array.SetFePos(pos + 1)
	if p.GetKey() == nil {
		EX_VAR(opline.GetResult().GetVar()).SetLong(p.GetH())
	} else {
		EX_VAR(opline.GetResult().GetVar()).SetStringCopy(p.GetKey())
	}
	variable_ptr = EX_VAR(opline.GetOp2().GetVar())
	ZendAssignToVariable(variable_ptr, value, IS_CV, executeData.IsCallUseStrictTypes())
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_CHECK_FUNC_ARG_SPEC_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var arg_num uint32 = opline.GetOp2().GetNum()
	if ARG_SHOULD_BE_SENT_BY_REF(EX(call).func_, arg_num) != 0 {
		ZEND_ADD_CALL_FLAG(EX(call), ZEND_CALL_SEND_ARG_BY_REF)
	} else {
		ZEND_DEL_CALL_FLAG(EX(call), ZEND_CALL_SEND_ARG_BY_REF)
	}
	ZEND_VM_NEXT_OPCODE()
}
