func ZEND_RETURN_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var retval_ptr *Zval
	var return_value *Zval
	var free_op1 ZendFreeOp
	retval_ptr = EX_VAR(opline.GetOp1().GetVar())
	return_value = EX(return_value)
	if IS_CV == IS_CV && retval_ptr.GetTypeInfo() == IS_UNDEF {
		retval_ptr = ZVAL_UNDEFINED_OP1()
		if return_value != nil {
			return_value.SetNull()
		}
	} else if return_value == nil {
		if (IS_CV & (IS_VAR | IS_TMP_VAR)) != 0 {
			if free_op1.IsRefcounted() && free_op1.DelRefcount() == 0 {
				RcDtorFunc(free_op1.GetCounted())
			}
		}
	} else {
		if (IS_CV & (IS_CONST | IS_TMP_VAR)) != 0 {
			ZVAL_COPY_VALUE(return_value, retval_ptr)
			if IS_CV == IS_CONST {
				if return_value.IsRefcounted() {
					return_value.AddRefcount()
				}
			}
		} else if IS_CV == IS_CV {
			for {
				if retval_ptr.IsRefcounted() {
					if !(retval_ptr.IsReference()) {
						if (EX_CALL_INFO() & ZEND_CALL_CODE) == 0 {
							var ref *ZendRefcounted = retval_ptr.GetCounted()
							ZVAL_COPY_VALUE(return_value, retval_ptr)
							if GC_MAY_LEAK(ref) {
								GcPossibleRoot(ref)
							}
							retval_ptr.SetNull()
							break
						} else {
							retval_ptr.AddRefcount()
						}
					} else {
						retval_ptr = Z_REFVAL_P(retval_ptr)
						if retval_ptr.IsRefcounted() {
							retval_ptr.AddRefcount()
						}
					}
				}
				ZVAL_COPY_VALUE(return_value, retval_ptr)
				break
			}
		} else {
			if retval_ptr.IsReference() {
				var ref *ZendRefcounted = retval_ptr.GetCounted()
				retval_ptr = Z_REFVAL_P(retval_ptr)
				ZVAL_COPY_VALUE(return_value, retval_ptr)
				if ref.DelRefcount() == 0 {
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if retval_ptr.IsRefcounted() {
					retval_ptr.AddRefcount()
				}
			} else {
				ZVAL_COPY_VALUE(return_value, retval_ptr)
			}
		}
	}
	return zend_leave_helper_SPEC(executeData)
}
func ZEND_RETURN_BY_REF_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var retval_ptr *Zval
	for {
		if (IS_CV&(IS_CONST|IS_TMP_VAR)) != 0 || IS_CV == IS_VAR && opline.GetExtendedValue() == ZEND_RETURNS_VALUE {

			/* Not supposed to happen, but we'll allow it */

			ZendError(E_NOTICE, "Only variable references should be returned by reference")
			retval_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
			if !(EX(return_value)) {

			} else {
				if IS_CV == IS_VAR && retval_ptr.IsReference() {
					ZVAL_COPY_VALUE(EX(return_value), retval_ptr)
					break
				}
				EX(return_value).SetNewRef(retval_ptr)
				if IS_CV == IS_CONST {
					retval_ptr.TryAddRefcount()
				}
			}
			break
		}
		retval_ptr = _get_zval_ptr_cv_BP_VAR_W(opline.GetOp1().GetVar(), executeData)
		if IS_CV == IS_VAR {
			ZEND_ASSERT(retval_ptr != EG__().GetUninitializedZval())
			if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(retval_ptr.IsReference()) {
				ZendError(E_NOTICE, "Only variable references should be returned by reference")
				if EX(return_value) {
					EX(return_value).SetNewRef(retval_ptr)
				}
				break
			}
		}
		if EX(return_value) {
			if retval_ptr.IsReference() {
				retval_ptr.AddRefcount()
			} else {
				ZVAL_MAKE_REF_EX(retval_ptr, 2)
			}
			EX(return_value).SetReference(retval_ptr.GetRef())
		}
		break
	}
	return zend_leave_helper_SPEC(executeData)
}
func ZEND_GENERATOR_RETURN_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var retval *Zval
	var generator *ZendGenerator = ZendGetRunningGenerator(executeData)
	retval = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)

	/* Copy return value into generator->retval */

	if (IS_CV & (IS_CONST | IS_TMP_VAR)) != 0 {
		ZVAL_COPY_VALUE(generator.GetRetval(), retval)
		if IS_CV == IS_CONST {
			if generator.GetRetval().IsRefcounted() {
				generator.GetRetval().AddRefcount()
			}
		}
	} else if IS_CV == IS_CV {
		ZVAL_COPY_DEREF(generator.GetRetval(), retval)
	} else {
		if retval.IsReference() {
			var ref *ZendRefcounted = retval.GetCounted()
			retval = Z_REFVAL_P(retval)
			ZVAL_COPY_VALUE(generator.GetRetval(), retval)
			if ref.DelRefcount() == 0 {
				EfreeSize(ref, b.SizeOf("zend_reference"))
			} else if retval.IsRefcounted() {
				retval.AddRefcount()
			}
		} else {
			ZVAL_COPY_VALUE(generator.GetRetval(), retval)
		}
	}

	/* Close the generator to free up resources */

	ZendGeneratorClose(generator, 1)

	/* Pass execution back to handling code */

	return -1

	/* Pass execution back to handling code */
}
func ZEND_THROW_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	value = EX_VAR(opline.GetOp1().GetVar())
	for {
		if IS_CV == IS_CONST || value.GetType() != IS_OBJECT {
			if (IS_CV&(IS_VAR|IS_CV)) != 0 && value.IsReference() {
				value = Z_REFVAL_P(value)
				if value.IsObject() {
					break
				}
			}
			if IS_CV == IS_CV && value.IsUndef() {
				ZVAL_UNDEFINED_OP1()
				if EG__().GetException() != nil {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Can only throw objects")
			HANDLE_EXCEPTION()
		}
		break
	}
	ZendExceptionSave()
	if IS_CV != IS_TMP_VAR {
		value.TryAddRefcount()
	}
	ZendThrowExceptionObject(value)
	ZendExceptionRestore()
	HANDLE_EXCEPTION()
}
func ZEND_SEND_VAR_SPEC_CV_INLINE_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var varptr *Zval
	var arg *Zval
	varptr = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CV && varptr.GetTypeInfo() == IS_UNDEF {
		ZVAL_UNDEFINED_OP1()
		arg = ZEND_CALL_VAR(EX(call), opline.GetResult().GetVar())
		arg.SetNull()
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	arg = ZEND_CALL_VAR(EX(call), opline.GetResult().GetVar())
	if IS_CV == IS_CV {
		ZVAL_COPY_DEREF(arg, varptr)
	} else {
		if varptr.IsReference() {
			var ref *ZendRefcounted = varptr.GetCounted()
			varptr = Z_REFVAL_P(varptr)
			ZVAL_COPY_VALUE(arg, varptr)
			if ref.DelRefcount() == 0 {
				EfreeSize(ref, b.SizeOf("zend_reference"))
			} else if arg.IsRefcounted() {
				arg.AddRefcount()
			}
		} else {
			ZVAL_COPY_VALUE(arg, varptr)
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
