	if ARG_MUST_BE_SENT_BY_REF(EX(call).func_, opline.GetOp2().GetNum()) != 0 {
		ZendParamMustBeRef(EX(call).func_, opline.GetOp2().GetNum())
	}
	arg = _get_zval_ptr_cv_deref_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
