func ZEND_BOOL_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var val *Zval
	val = EX_VAR(opline.GetOp1().GetVar())
	if val.GetTypeInfo() == IS_TRUE {
		EX_VAR(opline.GetResult().GetVar()).SetTrue()
	} else if val.GetTypeInfo() <= IS_TRUE {

		/* The result and op1 can be the same cv zval */

		var orig_val_type uint32 = val.GetTypeInfo()
		EX_VAR(opline.GetResult().GetVar()).SetFalse()
		if IS_CV == IS_CV && orig_val_type == IS_UNDEF {
			ZVAL_UNDEFINED_OP1()
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
	} else {
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), IZendIsTrue(val) != 0)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_CLONE_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var obj *Zval
	var ce *ZendClassEntry
	var scope *ZendClassEntry
	var clone *ZendFunction
	var clone_call ZendObjectCloneObjT
	obj = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && obj.IsUndef() {
		return zend_this_not_in_object_context_helper_SPEC(executeData)
	}
	for {
		if IS_CV == IS_CONST || IS_CV != IS_UNUSED && obj.GetType() != IS_OBJECT {
			if (IS_CV&(IS_VAR|IS_CV)) != 0 && obj.IsReference() {
				obj = Z_REFVAL_P(obj)
				if obj.IsObject() {
					break
				}
			}
			EX_VAR(opline.GetResult().GetVar()).SetUndef()
			if IS_CV == IS_CV && obj.IsUndef() {
				ZVAL_UNDEFINED_OP1()
				if EG__().GetException() != nil {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "__clone method called on non-object")
			HANDLE_EXCEPTION()
		}
		break
	}
	ce = Z_OBJCE_P(obj)
	clone = ce.GetClone()
	clone_call = Z_OBJ_HT_P(obj).GetCloneObj()
	if clone_call == nil {
		ZendThrowError(nil, "Trying to clone an uncloneable object of class %s", ce.GetName().GetVal())
		EX_VAR(opline.GetResult().GetVar()).SetUndef()
		HANDLE_EXCEPTION()
	}
	if clone != nil && !clone.IsPublic() {
		scope = EX(func_).op_array.scope
		if clone.GetScope() != scope {
			if clone.IsPrivate() || ZendCheckProtected(ZendGetFunctionRootClass(clone), scope) == 0 {
				ZendWrongCloneCall(clone, scope)
				EX_VAR(opline.GetResult().GetVar()).SetUndef()
				HANDLE_EXCEPTION()
			}
		}
	}
	EX_VAR(opline.GetResult().GetVar()).SetObject(clone_call(obj))
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_CAST_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var expr *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	var ht *HashTable
	expr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
	switch opline.GetExtendedValue() {
	case IS_NULL:
		result.SetNull()
	case _IS_BOOL:
		ZVAL_BOOL(result, ZendIsTrue(expr) != 0)
	case IS_LONG:
		result.SetLong(ZvalGetLong(expr))
	case IS_DOUBLE:
		result.SetDouble(ZvalGetDouble(expr))
	case IS_STRING:
		result.SetString(ZvalGetString(expr))
	default:
		if (IS_CV & (IS_VAR | IS_CV)) != 0 {
			expr = ZVAL_DEREF(expr)
		}

		/* If value is already of correct type, return it directly */

		if expr.IsType(opline.GetExtendedValue()) {
			ZVAL_COPY_VALUE(result, expr)
			if IS_CV == IS_CONST {
				if result.IsRefcounted() {
					result.AddRefcount()
				}
			} else if IS_CV != IS_TMP_VAR {
				if result.IsRefcounted() {
					result.AddRefcount()
				}
			}
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
		if opline.GetExtendedValue() == IS_ARRAY {
			if IS_CV == IS_CONST || expr.GetType() != IS_OBJECT || Z_OBJCE_P(expr) == ZendCeClosure {
				if expr.GetType() != IS_NULL {
					result.SetArray(ZendNewArray(1))
					expr = result.GetArr().IndexAddNewH(0, expr)
					if IS_CV == IS_CONST {
						if expr.IsRefcounted() {
							expr.AddRefcount()
						}
					} else {
						if expr.IsRefcounted() {
							expr.AddRefcount()
						}
					}
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			} else {
				var obj_ht *HashTable = ZendGetPropertiesFor(expr, ZEND_PROP_PURPOSE_ARRAY_CAST)
				if obj_ht != nil {

					/* fast copy */

					result.SetArray(ZendProptableToSymtable(obj_ht, Z_OBJCE_P(expr).GetDefaultPropertiesCount() != 0 || Z_OBJ_P(expr).GetHandlers() != &StdObjectHandlers || obj_ht.IsRecursive()))
					ZendReleaseProperties(obj_ht)
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			}
		} else {
			result.SetObject(ZendObjectsNew(ZendStandardClassDef))
			if expr.IsArray() {
				ht = ZendSymtableToProptable(expr.GetArr())
				if (ht.GetGcFlags() & IS_ARRAY_IMMUTABLE) != 0 {

					/* TODO: try not to duplicate immutable arrays as well ??? */

					ht = ZendArrayDup(ht)

					/* TODO: try not to duplicate immutable arrays as well ??? */

				}
				Z_OBJ_P(result).SetProperties(ht)
			} else if expr.GetType() != IS_NULL {
				ht = ZendNewArray(1)
				Z_OBJ_P(result).SetProperties(ht)
				expr = ht.KeyAddNew(ZSTR_KNOWN(ZEND_STR_SCALAR).GetStr(), expr)
				if IS_CV == IS_CONST {
					if expr.IsRefcounted() {
						expr.AddRefcount()
					}
				} else {
					if expr.IsRefcounted() {
						expr.AddRefcount()
					}
				}
			}
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INCLUDE_OR_EVAL_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var new_op_array *ZendOpArray
	var inc_filename *Zval
	inc_filename = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
	new_op_array = ZendIncludeOrEval(inc_filename, opline.GetExtendedValue())
	if EG__().GetException() != nil {
		if new_op_array != ZEND_FAKE_OP_ARRAY && new_op_array != nil {
			DestroyOpArray(new_op_array)
			EfreeSize(new_op_array, b.SizeOf("zend_op_array"))
		}
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	} else if new_op_array == ZEND_FAKE_OP_ARRAY {
		if RETURN_VALUE_USED(opline) {
			EX_VAR(opline.GetResult().GetVar()).SetTrue()
		}
	} else if new_op_array != nil {
		var return_value *Zval = nil
		var call *ZendExecuteData
		if RETURN_VALUE_USED(opline) {
			return_value = EX_VAR(opline.GetResult().GetVar())
		}
		new_op_array.SetScope(EX(func_).op_array.scope)
		call = ZendVmStackPushCallFrame(EX(This).GetTypeInfo()&ZEND_CALL_HAS_THIS|ZEND_CALL_NESTED_CODE|ZEND_CALL_HAS_SYMBOL_TABLE, (*ZendFunction)(new_op_array), 0, EX(This).GetPtr())
		if (EX_CALL_INFO() & ZEND_CALL_HAS_SYMBOL_TABLE) != 0 {
			call.SetSymbolTable(EX(symbol_table))
		} else {
			call.SetSymbolTable(ZendRebuildSymbolTable())
		}
		call.SetPrevExecuteData(executeData)
		IInitCodeExecuteData(call, new_op_array, return_value)
		if ZendExecuteEx == ExecuteEx {
			return 1
		} else {
			ZEND_ADD_CALL_FLAG(call, ZEND_CALL_TOP)
			ZendExecuteEx(call)
			ZendVmStackFreeCallFrame(call)
		}
		DestroyOpArray(new_op_array)
		EfreeSize(new_op_array, b.SizeOf("zend_op_array"))
		if EG__().GetException() != nil {
			ZendRethrowException(executeData)
			UNDEF_RESULT()
			HANDLE_EXCEPTION()
		}
	} else if RETURN_VALUE_USED(opline) {
		EX_VAR(opline.GetResult().GetVar()).SetFalse()
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_FE_RESET_R_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array_ptr *Zval
	var result *Zval
	array_ptr = _get_zval_ptr_cv_deref_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
	if array_ptr.IsArray() {
		result = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, array_ptr)
		if IS_CV != IS_TMP_VAR && result.IsRefcounted() {
			array_ptr.AddRefcount()
		}
		result.SetFePos(0)
		ZEND_VM_NEXT_OPCODE()
	} else if IS_CV != IS_CONST && array_ptr.IsObject() {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if Z_OBJ_P(array_ptr).GetProperties() != nil && Z_OBJ_P(array_ptr).GetProperties().GetRefcount() > 1 {
				if (Z_OBJ_P(array_ptr).GetProperties().GetGcFlags() & IS_ARRAY_IMMUTABLE) == 0 {
					Z_OBJ_P(array_ptr).GetProperties().DelRefcount()
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			result = EX_VAR(opline.GetResult().GetVar())
			ZVAL_COPY_VALUE(result, array_ptr)
			if IS_CV != IS_TMP_VAR {
				array_ptr.AddRefcount()
			}
			if properties.GetNNumOfElements() == 0 {
				result.SetFeIterIdx(uint32 - 1)
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			result.SetFeIterIdx(ZendHashIteratorAdd(properties, 0))
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 0, opline, executeData)
			if EG__().GetException() != nil {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		EX_VAR(opline.GetResult().GetVar()).SetUndef()
		EX_VAR(opline.GetResult().GetVar()).SetFeIterIdx(uint32 - 1)
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
func ZEND_FE_RESET_RW_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array_ptr *Zval
	var array_ref *Zval
	if IS_CV == IS_VAR || IS_CV == IS_CV {
		array_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
		array_ref = array_ptr
		if array_ref.IsReference() {
			array_ptr = Z_REFVAL_P(array_ref)
		}
	} else {
		array_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
		array_ref = array_ptr
	}
	if array_ptr.IsArray() {
		if IS_CV == IS_VAR || IS_CV == IS_CV {
			if array_ptr == array_ref {
				array_ref.SetNewRef(array_ref)
				array_ptr = Z_REFVAL_P(array_ref)
			}
			array_ref.AddRefcount()
			ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), array_ref)
		} else {
			array_ref = EX_VAR(opline.GetResult().GetVar())
			array_ref.SetNewRef(array_ptr)
			array_ptr = Z_REFVAL_P(array_ref)
		}
		if IS_CV == IS_CONST {
			array_ptr.SetArray(ZendArrayDup(array_ptr.GetArr()))
		} else {
			SEPARATE_ARRAY(array_ptr)
		}
		EX_VAR(opline.GetResult().GetVar()).SetFeIterIdx(ZendHashIteratorAdd(array_ptr.GetArr(), 0))
		if IS_CV == IS_VAR {

		}
		ZEND_VM_NEXT_OPCODE()
	} else if IS_CV != IS_CONST && array_ptr.IsObject() {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if IS_CV == IS_VAR || IS_CV == IS_CV {
				if array_ptr == array_ref {
					array_ref.SetNewRef(array_ref)
					array_ptr = Z_REFVAL_P(array_ref)
				}
				array_ref.AddRefcount()
				ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), array_ref)
			} else {
				array_ptr = EX_VAR(opline.GetResult().GetVar())
				ZVAL_COPY_VALUE(array_ptr, array_ref)
			}
			if Z_OBJ_P(array_ptr).GetProperties() != nil && Z_OBJ_P(array_ptr).GetProperties().GetRefcount() > 1 {
				if (Z_OBJ_P(array_ptr).GetProperties().GetGcFlags() & IS_ARRAY_IMMUTABLE) == 0 {
					Z_OBJ_P(array_ptr).GetProperties().DelRefcount()
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			if properties.GetNNumOfElements() == 0 {
				EX_VAR(opline.GetResult().GetVar()).SetFeIterIdx(uint32 - 1)
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			EX_VAR(opline.GetResult().GetVar()).SetFeIterIdx(ZendHashIteratorAdd(properties, 0))
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 1, opline, executeData)
			if IS_CV == IS_VAR {

			}
			if EG__().GetException() != nil {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		EX_VAR(opline.GetResult().GetVar()).SetUndef()
		EX_VAR(opline.GetResult().GetVar()).SetFeIterIdx(uint32 - 1)
		if IS_CV == IS_VAR {

		}
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
func ZEND_JMP_SET_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var ref *Zval = nil
	var ret int
	value = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
	if (IS_CV == IS_VAR || IS_CV == IS_CV) && value.IsReference() {
		if IS_CV == IS_VAR {
			ref = value
		}
		value = Z_REFVAL_P(value)
	}
	ret = IZendIsTrue(value)
	if EG__().GetException() != nil {
		EX_VAR(opline.GetResult().GetVar()).SetUndef()
		HANDLE_EXCEPTION()
	}
	if ret != 0 {
		var result *Zval = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, value)
		if IS_CV == IS_CONST {
			if result.IsRefcounted() {
				result.AddRefcount()
			}
		} else if IS_CV == IS_CV {
			if result.IsRefcounted() {
				result.AddRefcount()
			}
		} else if IS_CV == IS_VAR && ref != nil {
			var r *ZendReference = ref.GetRef()
			if r.DelRefcount() == 0 {
				EfreeSize(r, b.SizeOf("zend_reference"))
			} else if result.IsRefcounted() {
				result.AddRefcount()
			}
		}
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_COALESCE_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var ref *Zval = nil
	value = _get_zval_ptr_cv_BP_VAR_IS(opline.GetOp1().GetVar(), executeData)
	if (IS_CV&(IS_VAR|IS_CV)) != 0 && value.IsReference() {
		if (IS_CV & IS_VAR) != 0 {
			ref = value
		}
		value = Z_REFVAL_P(value)
	}
	if value.GetType() > IS_NULL {
		var result *Zval = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, value)
		if IS_CV == IS_CONST {
			if result.IsRefcounted() {
				result.AddRefcount()
			}
		} else if IS_CV == IS_CV {
			if result.IsRefcounted() {
				result.AddRefcount()
			}
		} else if (IS_CV&IS_VAR) != 0 && ref != nil {
			var r *ZendReference = ref.GetRef()
			if r.DelRefcount() == 0 {
				EfreeSize(r, b.SizeOf("zend_reference"))
			} else if result.IsRefcounted() {
				result.AddRefcount()
			}
		}
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_QM_ASSIGN_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	value = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CV && value.IsUndef() {
		ZVAL_UNDEFINED_OP1()
		result.SetNull()
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	if IS_CV == IS_CV {
		ZVAL_COPY_DEREF(result, value)
	} else if IS_CV == IS_VAR {
		if value.IsReference() {
			ZVAL_COPY_VALUE(result, Z_REFVAL_P(value))
			if value.DelRefcount() == 0 {
				EfreeSize(value.GetRef(), b.SizeOf("zend_reference"))
			} else if result.IsRefcounted() {
				result.AddRefcount()
			}
		} else {
			ZVAL_COPY_VALUE(result, value)
		}
	} else {
		ZVAL_COPY_VALUE(result, value)
		if IS_CV == IS_CONST {
			if result.IsRefcounted() {
				result.AddRefcount()
			}
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_YIELD_FROM_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(executeData)
	var val *Zval
	val = _get_zval_ptr_cv_deref_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
	if generator.IsForcedClose() {
		ZendThrowError(nil, "Cannot use \"yield from\" in a force-closed generator")
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}
	if val.IsArray() {
		ZVAL_COPY_VALUE(generator.GetValues(), val)
		if IS_CV != IS_TMP_VAR && val.IsRefcounted() {
			val.AddRefcount()
		}
		generator.GetValues().GetFePos() = 0
	} else if IS_CV != IS_CONST && val.IsObject() && Z_OBJCE_P(val).GetGetIterator() != nil {
		var ce *ZendClassEntry = Z_OBJCE_P(val)
		if ce == ZendCeGenerator {
			var new_gen *ZendGenerator = (*ZendGenerator)(val.GetObj())
			if IS_CV != IS_TMP_VAR {
				val.AddRefcount()
			}
			if new_gen.GetRetval().IsUndef() {
				if ZendGeneratorGetCurrent(new_gen) == generator {
					ZendThrowError(nil, "Impossible to yield from the Generator being currently run")
					ZvalPtrDtor(val)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				} else {
					ZendGeneratorYieldFrom(generator, new_gen)
				}
			} else if new_gen.GetExecuteData() == nil {
				ZendThrowError(nil, "Generator passed to yield from was aborted without proper return and is unable to continue")
				ZvalPtrDtor(val)
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			} else {
				if RETURN_VALUE_USED(opline) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), new_gen.GetRetval())
				}
				ZEND_VM_NEXT_OPCODE()
			}
		} else {
			var iter *ZendObjectIterator = ce.GetGetIterator()(ce, val, 0)
			if iter == nil || EG__().GetException() != nil {
				if EG__().GetException() == nil {
					ZendThrowError(nil, "Object of type %s did not create an Iterator", ce.GetName().GetVal())
				}
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			}
			iter.SetIndex(0)
			if iter.GetFuncs().GetRewind() != nil {
				iter.GetFuncs().GetRewind()(iter)
				if EG__().GetException() != nil {
					OBJ_RELEASE(iter.GetStd())
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				}
			}
			generator.GetValues().SetObject(iter.GetStd())
		}
	} else {
		ZendThrowError(nil, "Can use \"yield from\" only with arrays and Traversables")
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}

	/* This is the default return value
	 * when the expression is a Generator, it will be overwritten in zend_generator_resume() */

	if RETURN_VALUE_USED(opline) {
		EX_VAR(opline.GetResult().GetVar()).SetNull()
	}

	/* This generator has no send target (though the generator we delegate to might have one) */

	generator.SetSendTarget(nil)

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in executeData so we don't resume at an old position. */

	return -1
}
func ZEND_STRLEN_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	value = EX_VAR(opline.GetOp1().GetVar())
	if value.IsString() {
		EX_VAR(opline.GetResult().GetVar()).SetLong(Z_STRLEN_P(value))
		ZEND_VM_NEXT_OPCODE()
	} else {
		var strict ZendBool
		if (IS_CV&(IS_VAR|IS_CV)) != 0 && value.IsReference() {
			value = Z_REFVAL_P(value)
			if value.IsString() {
				EX_VAR(opline.GetResult().GetVar()).SetLong(Z_STRLEN_P(value))
				ZEND_VM_NEXT_OPCODE()
			}
		}
		if IS_CV == IS_CV && value.IsUndef() {
			value = ZVAL_UNDEFINED_OP1()
		}
		strict = executeData.IsCallUseStrictTypes()
		for {
			if strict == 0 {
				var str *ZendString
				var tmp Zval
				ZVAL_COPY(&tmp, value)
				if ZendParseArgStrWeak(&tmp, &str) != 0 {
					EX_VAR(opline.GetResult().GetVar()).SetLong(str.GetLen())
					ZvalPtrDtor(&tmp)
					break
				}
				ZvalPtrDtor(&tmp)
			}
			if EG__().GetException() == nil {
				ZendInternalTypeError(strict, "strlen() expects parameter 1 to be string, %s given", ZendGetTypeByConst(value.GetType()))
			}
			EX_VAR(opline.GetResult().GetVar()).SetNull()
			break
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_TYPE_CHECK_SPEC_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result int = 0
	value = EX_VAR(opline.GetOp1().GetVar())
	if (opline.GetExtendedValue() >> uint32(value.GetType()) & 1) != 0 {
	type_check_resource:
		if value.GetType() != IS_RESOURCE || nil != ZendRsrcListGetRsrcType(value.GetRes()) {
			result = 1
		}
	} else if (IS_CV&(IS_CV|IS_VAR)) != 0 && value.IsReference() {
		value = Z_REFVAL_P(value)
		if (opline.GetExtendedValue() >> uint32(value.GetType()) & 1) != 0 {
			goto type_check_resource
		}
	} else if IS_CV == IS_CV && value.IsUndef() {
		result = (1 << IS_NULL & opline.GetExtendedValue()) != 0
		ZVAL_UNDEFINED_OP1()
		if EG__().GetException() != nil {
			EX_VAR(opline.GetResult().GetVar()).SetUndef()
			HANDLE_EXCEPTION()
		}
	}
	if (IS_CV & (IS_TMP_VAR | IS_VAR)) != 0 {
		ZEND_VM_SMART_BRANCH(result, 1)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result != 0)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	} else {
		ZEND_VM_SMART_BRANCH(result, 0)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result != 0)
		ZEND_VM_NEXT_OPCODE()
	}
}
