func ZEND_ASSIGN_OBJ_SPEC_CV_CONST_OP_DATA_CONST_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var object *Zval
	var property *Zval
	var value *Zval
	var tmp Zval
	object = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && object.IsUndef() {
		return zend_this_not_in_object_context_helper_SPEC(executeData)
	}
	property = RT_CONSTANT(opline, opline.GetOp2())
	value = RT_CONSTANT(opline+1, (opline + 1).GetOp1())
	if IS_CV != IS_UNUSED && object.GetType() != IS_OBJECT {
		if object.IsReference() && Z_REFVAL_P(object).IsObject() {
			object = Z_REFVAL_P(object)
			goto assign_object
		}
		object = MakeRealObject(object, property, opline, executeData)
		if object == nil {
			value = EG__().GetUninitializedZval()
			goto free_and_exit_assign_obj
		}
	}
assign_object:
	if IS_CONST == IS_CONST && Z_OBJCE_P(object) == CACHED_PTR(opline.GetExtendedValue()) {
		var cache_slot *any = CACHE_ADDR(opline.GetExtendedValue())
		var prop_offset uintPtr = uintPtr(CACHED_PTR_EX(cache_slot + 1))
		var zobj *ZendObject = object.GetObj()
		var property_val *Zval
		if IS_VALID_PROPERTY_OFFSET(prop_offset) {
			property_val = OBJ_PROP(zobj, prop_offset)
			if property_val.GetType() != IS_UNDEF {
				var prop_info *ZendPropertyInfo = (*ZendPropertyInfo)(CACHED_PTR_EX(cache_slot + 2))
				if prop_info != nil {
					value = ZendAssignToTypedProp(prop_info, property_val, value, executeData)
					goto free_and_exit_assign_obj
				} else {
				fast_assign_obj:
					value = ZendAssignToVariable(property_val, value, IS_CONST, executeData.IsCallUseStrictTypes())
					if RETURN_VALUE_USED(opline) {
						ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
					}
					goto exit_assign_obj
				}
			}
		} else {
			if zobj.GetProperties() != nil {
				if zobj.GetProperties().GetRefcount() > 1 {
					if (zobj.GetProperties().GetGcFlags() & IS_ARRAY_IMMUTABLE) == 0 {
						zobj.GetProperties().DelRefcount()
					}
					zobj.SetProperties(ZendArrayDup(zobj.GetProperties()))
				}
				property_val = zobj.GetProperties().KeyFind(property.GetStr().GetStr())
				if property_val != nil {
					goto fast_assign_obj
				}
			}
			if zobj.GetCe().GetSet() == nil {
				if zobj.GetProperties() == nil {
					RebuildObjectProperties(zobj)
				}
				if IS_CONST == IS_CONST {
					if value.IsRefcounted() {
						value.AddRefcount()
					}
				} else if IS_CONST != IS_TMP_VAR {
					if value.IsReference() {
						if IS_CONST == IS_VAR {
							var ref *ZendReference = value.GetRef()
							if ref.DelRefcount() == 0 {
								ZVAL_COPY_VALUE(&tmp, Z_REFVAL_P(value))
								EfreeSize(ref, b.SizeOf("zend_reference"))
								value = &tmp
							} else {
								value = Z_REFVAL_P(value)
								value.TryAddRefcount()
							}
						} else {
							value = Z_REFVAL_P(value)
							value.TryAddRefcount()
						}
					} else if IS_CONST == IS_CV {
						value.TryAddRefcount()
					}
				}
				zobj.GetProperties().KeyAddNew(property.GetStr().GetStr(), value)
				if RETURN_VALUE_USED(opline) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
				}
				goto exit_assign_obj
			}
		}
	}
	if IS_CONST == IS_CV || IS_CONST == IS_VAR {
		value = ZVAL_DEREF(value)
	}
	value = Z_OBJ_HT_P(object).GetWriteProperty()(object, property, value, b.CondF1(IS_CONST == IS_CONST, func() *any { return CACHE_ADDR(opline.GetExtendedValue()) }, nil))
free_and_exit_assign_obj:
	if RETURN_VALUE_USED(opline) {
		ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
	}
exit_assign_obj:

	/* assign_obj has two opcodes! */

	OPLINE = EX(opline) + 2
	return 0
}
