	if retval != EX_VAR(opline.GetResult().GetVar()) {
	fetch_obj_r_copy:
		ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), retval)
	} else if retval.IsReference() {
		ZendUnwrapReference(retval)
	}
