func ZEND_ASSIGN_DIM_OP_SPEC_CV_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op_data1 ZendFreeOp
	var var_ptr *Zval
	var value *Zval
	var container *Zval
	var dim *Zval
	container = EX_VAR(opline.GetOp1().GetVar())
	if container.IsArray() {
	assign_dim_op_array:
		SEPARATE_ARRAY(container)
	assign_dim_op_new_array:
		dim = nil
		if IS_UNUSED == IS_UNUSED {
			var_ptr = container.GetArr().NextIndexInsert(EG__().GetUninitializedZval())
			if var_ptr == nil {
				ZendCannotAddElement()
				goto assign_dim_op_ret_null
			}
		} else {
			if IS_UNUSED == IS_CONST {
				var_ptr = zend_fetch_dimension_address_inner_RW_CONST(container.GetArr(), dim, executeData)
			} else {
				var_ptr = zend_fetch_dimension_address_inner_RW(container.GetArr(), dim, executeData)
			}
			if var_ptr == nil {
				goto assign_dim_op_ret_null
			}
		}
		value = GetOpDataZvalPtrR((opline + 1).GetOp1Type(), (opline + 1).GetOp1(), &free_op_data1)
		for {
			if IS_UNUSED != IS_UNUSED && var_ptr.IsReference() {
				var ref *ZendReference = var_ptr.GetRef()
				var_ptr = Z_REFVAL_P(var_ptr)
				if ZEND_REF_HAS_TYPE_SOURCES(ref) {
					ZendBinaryAssignOpTypedRef(ref, value, opline, executeData)
					break
				}
			}
			ZendBinaryOp(var_ptr, var_ptr, value, opline)
			break
		}
		if RETURN_VALUE_USED(opline) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), var_ptr)
		}
		FREE_OP(free_op_data1)
	} else {
		if container.IsReference() {
			container = Z_REFVAL_P(container)
			if container.IsArray() {
				goto assign_dim_op_array
			}
		}
		dim = nil
		if container.IsObject() {
			if IS_UNUSED == IS_CONST && dim.GetU2Extra() == ZEND_EXTRA_VALUE {
				dim++
			}
			ZendBinaryAssignOpObjDim(container, dim, opline, executeData)
		} else if container.GetType() <= IS_FALSE {
			if IS_CV == IS_CV && container.GetTypeInfo() == IS_UNDEF {
				ZVAL_UNDEFINED_OP1()
			}
			container.SetArray(ZendNewArray(8))
			goto assign_dim_op_new_array
		} else {
			ZendBinaryAssignOpDimSlow(container, dim, opline, executeData)
		assign_dim_op_ret_null:
			FREE_UNFETCHED_OP((opline + 1).GetOp1Type(), (opline + 1).GetOp1().GetVar())
			if RETURN_VALUE_USED(opline) {
				EX_VAR(opline.GetResult().GetVar()).SetNull()
			}
		}
	}
	OPLINE = EX(opline) + 2
	return 0
}
func zend_fetch_var_address_helper_SPEC_CV_UNUSED(type_ int, executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var varname *Zval
	var retval *Zval
	var name *ZendString
	var tmp_name *ZendString
	var target_symbol_table *HashTable
	varname = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CONST {
		name = varname.GetStr()
	} else if varname.IsString() {
		name = varname.GetStr()
		tmp_name = nil
	} else {
		if IS_CV == IS_CV && varname.IsUndef() {
			ZVAL_UNDEFINED_OP1()
		}
		name = ZvalTryGetTmpString(varname, &tmp_name)
		if name == nil {
			EX_VAR(opline.GetResult().GetVar()).SetUndef()
			HANDLE_EXCEPTION()
		}
	}
	target_symbol_table = ZendGetTargetSymbolTable(opline.GetExtendedValue(), executeData)
	retval = target_symbol_table.KeyFind(name.GetStr())
	if retval == nil {
		if ZendStringEquals(name, ZSTR_KNOWN(ZEND_STR_THIS)) != 0 {
		fetch_this:
			ZendFetchThisVar(type_, opline, executeData)
			if IS_CV != IS_CONST {
				ZendTmpStringRelease(tmp_name)
			}
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
		if type_ == BP_VAR_W {
			retval = target_symbol_table.KeyAddNew(name.GetStr(), EG__().GetUninitializedZval())
		} else if type_ == BP_VAR_IS {
			retval = EG__().GetUninitializedZval()
		} else {
			ZendError(E_NOTICE, "Undefined variable: %s", name.GetVal())
			if type_ == BP_VAR_RW {
				retval = target_symbol_table.KeyUpdate(name.GetStr(), EG__().GetUninitializedZval())
			} else {
				retval = EG__().GetUninitializedZval()
			}
		}
	} else if retval.IsIndirect() {
		retval = retval.GetZv()
		if retval.IsUndef() {
			if ZendStringEquals(name, ZSTR_KNOWN(ZEND_STR_THIS)) != 0 {
				goto fetch_this
			}
			if type_ == BP_VAR_W {
				retval.SetNull()
			} else if type_ == BP_VAR_IS {
				retval = EG__().GetUninitializedZval()
			} else {
				ZendError(E_NOTICE, "Undefined variable: %s", name.GetVal())
				if type_ == BP_VAR_RW {
					retval.SetNull()
				} else {
					retval = EG__().GetUninitializedZval()
				}
			}
		}
	}
	if (opline.GetExtendedValue() & ZEND_FETCH_GLOBAL_LOCK) == 0 {

	}
	if IS_CV != IS_CONST {
		ZendTmpStringRelease(tmp_name)
	}
	ZEND_ASSERT(retval != nil)
	if type_ == BP_VAR_R || type_ == BP_VAR_IS {
		ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), retval)
	} else {
		EX_VAR(opline.GetResult().GetVar()).SetIndirect(retval)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
