func ZEND_MAKE_REF_SPEC_CV_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var op1 *Zval = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CV {
		if op1.IsUndef() {
			op1.SetNewEmptyRef()
			op1.SetRefcount(2)
			Z_REFVAL_P(op1).SetNull()
			EX_VAR(opline.GetResult().GetVar()).SetReference(op1.GetRef())
		} else {
			if op1.IsReference() {
				op1.AddRefcount()
			} else {
				ZVAL_MAKE_REF_EX(op1, 2)
			}
			EX_VAR(opline.GetResult().GetVar()).SetReference(op1.GetRef())
		}
	} else if op1.IsIndirect() {
		op1 = op1.GetZv()
		if !(op1.IsReference()) {
			ZVAL_MAKE_REF_EX(op1, 2)
		} else {
			op1.GetRef().AddRefcount()
		}
		EX_VAR(opline.GetResult().GetVar()).SetReference(op1.GetRef())
	} else {
		ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), op1)
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_COUNT_SPEC_CV_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var op1 *Zval
	var count ZendLong
	op1 = EX_VAR(opline.GetOp1().GetVar())
	for true {
		if op1.IsArray() {
			count = op1.GetArr().Count()
			break
		} else if op1.IsObject() {

			/* first, we check if the handler is defined */

			if Z_OBJ_HT_P(op1).GetCountElements() != nil {
				if SUCCESS == Z_OBJ_HT_P(op1).GetCountElements()(op1, &count) {
					break
				}
				if EG__().GetException() != nil {
					count = 0
					break
				}
			}

			/* if not and the object implements Countable we call its count() method */

			if InstanceofFunction(Z_OBJCE_P(op1), ZendCeCountable) != 0 {
				var retval Zval
				ZendCallMethodWith0Params(op1, nil, nil, "count", &retval)
				count = ZvalGetLong(&retval)
				ZvalPtrDtor(&retval)
				break
			}

			/* If There's no handler and it doesn't implement Countable then add a warning */

			count = 1

			/* If There's no handler and it doesn't implement Countable then add a warning */

		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && op1.IsReference() {
			op1 = Z_REFVAL_P(op1)
			continue
		} else if op1.GetType() <= IS_NULL {
			if IS_CV == IS_CV && op1.IsUndef() {
				ZVAL_UNDEFINED_OP1()
			}
			count = 0
		} else {
			count = 1
		}
		ZendError(E_WARNING, "%s(): Parameter must be an array or an object that implements Countable", b.Cond(opline.GetExtendedValue() != 0, "sizeof", "count"))
		break
	}
	EX_VAR(opline.GetResult().GetVar()).SetLong(count)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_GET_CLASS_SPEC_CV_UNUSED_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if IS_CV == IS_UNUSED {
		if !(EX(func_).common.scope) {
			ZendError(E_WARNING, "get_class() called without object from outside a class")
			EX_VAR(opline.GetResult().GetVar()).SetFalse()
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			EX_VAR(opline.GetResult().GetVar()).SetStringCopy(EX(func_).common.scope.name)
			ZEND_VM_NEXT_OPCODE()
		}
	} else {
		var op1 *Zval
		op1 = EX_VAR(opline.GetOp1().GetVar())
		for true {
			if op1.IsObject() {
				EX_VAR(opline.GetResult().GetVar()).SetStringCopy(Z_OBJCE_P(op1).GetName())
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && op1.IsReference() {
				op1 = Z_REFVAL_P(op1)
				continue
			} else {
				if IS_CV == IS_CV && op1.IsUndef() {
					ZVAL_UNDEFINED_OP1()
				}
				ZendError(E_WARNING, "get_class() expects parameter 1 to be object, %s given", ZendGetTypeByConst(op1.GetType()))
				EX_VAR(opline.GetResult().GetVar()).SetFalse()
			}
			break
		}
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
}
