func ZEND_INIT_METHOD_CALL_SPEC_CV_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var free_op1 ZendFreeOp
	var object *Zval
	var fbc *ZendFunction
	var called_scope *ZendClassEntry
	var obj *ZendObject
	var call *ZendExecuteData
	var call_info uint32
	object = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && object.IsUndef() {
		return zend_this_not_in_object_context_helper_SPEC(executeData)
	}
	if IS_CV != IS_CONST {
		function_name = EX_VAR(opline.GetOp2().GetVar())
	}
	if IS_CV != IS_CONST && function_name.GetType() != IS_STRING {
		for {
			if (IS_CV&(IS_VAR|IS_CV)) != 0 && function_name.IsReference() {
				function_name = Z_REFVAL_P(function_name)
				if function_name.IsString() {
					break
				}
			} else if IS_CV == IS_CV && function_name.IsUndef() {
				ZVAL_UNDEFINED_OP2()
				if EG__().GetException() != nil {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Method name must be a string")
			HANDLE_EXCEPTION()
			break
		}
	}
	if IS_CV != IS_UNUSED {
		for {
			if IS_CV == IS_CONST || object.GetType() != IS_OBJECT {
				if (IS_CV&(IS_VAR|IS_CV)) != 0 && object.IsReference() {
					object = Z_REFVAL_P(object)
					if object.IsObject() {
						break
					}
				}
				if IS_CV == IS_CV && object.IsUndef() {
					object = ZVAL_UNDEFINED_OP1()
					if EG__().GetException() != nil {
						if IS_CV != IS_CONST {

						}
						HANDLE_EXCEPTION()
					}
				}
				if IS_CV == IS_CONST {
					function_name = EX_VAR(opline.GetOp2().GetVar())
				}
				ZendInvalidMethodCall(object, function_name)
				HANDLE_EXCEPTION()
			}
			break
		}
	}
	obj = object.GetObj()
	called_scope = obj.GetCe()
	if IS_CV == IS_CONST && CACHED_PTR(opline.GetResult().GetNum()) == called_scope {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else {
		var orig_obj *ZendObject = obj
		if IS_CV == IS_CONST {
			function_name = EX_VAR(opline.GetOp2().GetVar())
		}

		/* First, locate the function. */

		fbc = obj.GetHandlers().GetGetMethod()(&obj, function_name.GetStr(), b.CondF1(IS_CV == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		if fbc == nil {
			if EG__().GetException() == nil {
				ZendUndefinedMethod(obj.GetCe(), function_name.GetStr())
			}
			HANDLE_EXCEPTION()
		}
		if IS_CV == IS_CONST && fbc.GetType() <= ZEND_USER_FUNCTION && !fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE) && obj == orig_obj {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), called_scope, fbc)
		}
		if (IS_CV&(IS_VAR|IS_TMP_VAR)) != 0 && obj != orig_obj {

			/* Reset "object" to trigger reference counting */

			object = nil

			/* Reset "object" to trigger reference counting */

		}
		if fbc.GetType() == ZEND_USER_FUNCTION && !(RUN_TIME_CACHE(fbc.GetOpArray())) {
			InitFuncRunTimeCache(fbc.GetOpArray())
		}
	}
	if IS_CV != IS_CONST {

	}
	call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
	if fbc.IsStatic() {
		if (IS_CV&(IS_VAR|IS_TMP_VAR)) != 0 && EG__().GetException() != nil {
			HANDLE_EXCEPTION()
		}

		/* call static method */

		obj = (*ZendObject)(called_scope)
		call_info = ZEND_CALL_NESTED_FUNCTION
	} else if (IS_CV & (IS_VAR | IS_TMP_VAR | IS_CV)) != 0 {
		if IS_CV == IS_CV {
			obj.AddRefcount()
		} else if free_op1 != object {
			obj.AddRefcount()
		}

		/* CV may be changed indirectly (e.g. when it's a reference) */

		call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS | ZEND_CALL_RELEASE_THIS

		/* CV may be changed indirectly (e.g. when it's a reference) */

	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), obj)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ADD_ARRAY_ELEMENT_SPEC_CV_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var expr_ptr *Zval
	var new_expr Zval
	if (IS_CV == IS_VAR || IS_CV == IS_CV) && (opline.GetExtendedValue()&ZEND_ARRAY_ELEMENT_REF) != 0 {
		expr_ptr = _get_zval_ptr_cv_BP_VAR_W(opline.GetOp1().GetVar(), executeData)
		if expr_ptr.IsReference() {
			expr_ptr.AddRefcount()
		} else {
			ZVAL_MAKE_REF_EX(expr_ptr, 2)
		}
	} else {
		expr_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), executeData)
		if IS_CV == IS_TMP_VAR {

		} else if IS_CV == IS_CONST {
			expr_ptr.TryAddRefcount()
		} else if IS_CV == IS_CV {
			expr_ptr = ZVAL_DEREF(expr_ptr)
			expr_ptr.TryAddRefcount()
		} else {
			if expr_ptr.IsReference() {
				var ref *ZendRefcounted = expr_ptr.GetCounted()
				expr_ptr = Z_REFVAL_P(expr_ptr)
				if ref.DelRefcount() == 0 {
					ZVAL_COPY_VALUE(&new_expr, expr_ptr)
					expr_ptr = &new_expr
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if expr_ptr.IsRefcounted() {
					expr_ptr.AddRefcount()
				}
			}
		}
	}
	if IS_CV != IS_UNUSED {
		var offset *Zval = EX_VAR(opline.GetOp2().GetVar())
		var str *ZendString
		var hval ZendUlong
	add_again:
		if offset.IsString() {
			str = offset.GetStr()
			if IS_CV != IS_CONST {
				if ZEND_HANDLE_NUMERIC(str, &hval) {
					goto num_index
				}
			}
		str_index:
			EX_VAR(opline.GetResult().GetVar()).GetArr().KeyUpdate(str.GetStr(), expr_ptr)
		} else if offset.IsLong() {
			hval = offset.GetLval()
		num_index:
			EX_VAR(opline.GetResult().GetVar()).GetArr().IndexUpdateH(hval, expr_ptr)
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && offset.IsReference() {
			offset = Z_REFVAL_P(offset)
			goto add_again
		} else if offset.IsNull() {
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else if offset.IsDouble() {
			hval = ZendDvalToLval(offset.GetDval())
			goto num_index
		} else if offset.IsFalse() {
			hval = 0
			goto num_index
		} else if offset.IsTrue() {
			hval = 1
			goto num_index
		} else if offset.IsResource() {
			ZendUseResourceAsOffset(offset)
			hval = Z_RES_HANDLE_P(offset)
			goto num_index
		} else if IS_CV == IS_CV && offset.IsUndef() {
			ZVAL_UNDEFINED_OP2()
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else {
			ZendIllegalOffset()
			ZvalPtrDtorNogc(expr_ptr)
		}
	} else {
		if EX_VAR(opline.GetResult().GetVar()).GetArr().NextIndexInsert(expr_ptr) == nil {
			ZendCannotAddElement()
			ZvalPtrDtorNogc(expr_ptr)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_ARRAY_SPEC_CV_CV_HANDLER(executeData *ZendExecuteData) int {
	var array *Zval
	var size uint32
	var opline *ZendOp = EX(opline)
	array = EX_VAR(opline.GetResult().GetVar())
	if IS_CV != IS_UNUSED {
		size = opline.GetExtendedValue() >> ZEND_ARRAY_SIZE_SHIFT
		array.SetArray(ZendNewArray(size))

		/* Explicitly initialize array as not-packed if flag is set */

		if (opline.GetExtendedValue() & ZEND_ARRAY_NOT_PACKED) != 0 {
			ZendHashRealInitMixed(array.GetArr())
		}
		return ZEND_ADD_ARRAY_ELEMENT_SPEC_CV_CV_HANDLER(executeData)
	} else {
		array.SetArray(ZendNewArray(0))
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_UNSET_DIM_SPEC_CV_CV_HANDLER(executeData *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var offset *Zval
	var hval ZendUlong
	var key *ZendString
	container = EX_VAR(opline.GetOp1().GetVar())
	offset = EX_VAR(opline.GetOp2().GetVar())
	for {
		if container.IsArray() {
			var ht *HashTable
		unset_dim_array:
			SEPARATE_ARRAY(container)
			ht = container.GetArr()
		offset_again:
			if offset.IsString() {
				key = offset.GetStr()
				if IS_CV != IS_CONST {
					if ZEND_HANDLE_NUMERIC(key, &hval) {
						goto num_index_dim
					}
				}
			str_index_dim:
				if ht == EG__().GetSymbolTable() {
					ZendDeleteGlobalVariable(key)
				} else {
					ZendHashDel(ht, key)
				}
			} else if offset.IsLong() {
				hval = offset.GetLval()
			num_index_dim:
				ZendHashIndexDel(ht, hval)
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && offset.IsReference() {
				offset = Z_REFVAL_P(offset)
				goto offset_again
			} else if offset.IsDouble() {
				hval = ZendDvalToLval(offset.GetDval())
				goto num_index_dim
			} else if offset.IsNull() {
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else if offset.IsFalse() {
				hval = 0
				goto num_index_dim
			} else if offset.IsTrue() {
				hval = 1
				goto num_index_dim
			} else if offset.IsResource() {
				hval = Z_RES_HANDLE_P(offset)
				goto num_index_dim
			} else if IS_CV == IS_CV && offset.IsUndef() {
				ZVAL_UNDEFINED_OP2()
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else {
				ZendError(E_WARNING, "Illegal offset type in unset")
			}
			break
		} else if container.IsReference() {
			container = Z_REFVAL_P(container)
			if container.IsArray() {
				goto unset_dim_array
			}
		}
		if IS_CV == IS_CV && container.IsUndef() {
			container = ZVAL_UNDEFINED_OP1()
		}
		if IS_CV == IS_CV && offset.IsUndef() {
			offset = ZVAL_UNDEFINED_OP2()
		}
		if container.IsObject() {
			if IS_CV == IS_CONST && offset.GetU2Extra() == ZEND_EXTRA_VALUE {
				offset++
			}
			Z_OBJ_HT_P(container).GetUnsetDimension()(container, offset)
		} else if IS_CV != IS_UNUSED && container.IsString() {
			ZendThrowError(nil, "Cannot unset string offsets")
		}
		break
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
